// ---------------------------------------------------------------------------
// Rendering engine
// ---------------------------------------------------------------------------
// A "sprite frame" is a matrix: an array of equal-length strings where each
// character is a key into PALETTE ('.' / ' ' == transparent). The engine paints
// one ctx.fillRect per opaque cell, scaled up by `pixelSize` for the chunky
// retro-pixel look. Nothing here touches game logic — it is pure drawing.

// Layout seed for the AFK curse-pressure darkening (afk2_gen.js band C tableau).
// Fixed, so the tongues/folds/petals land in the same places every session.
const CURSE_SEED = 9;

export class SpriteManager {
    /**
     * Paint a matrix at a top-left origin (in world/canvas space).
     * @param {object} opts { flip, alpha, tint }  tint overrides every opaque
     *        pixel with one color (used for the white hit-flash / telegraphs).
     */
    static drawMatrix(ctx, matrix, originX, originY, pixelSize, opts = {}) {
        if (!matrix || !matrix.length) return;
        // `palette` lets a caller resolve keys against a per-sheet palette instead
        // of the shared global PALETTE (the redesigned boss/hero idle sheets reuse
        // the same key characters for different colors — see BOSS_REDESIGN_PALETTE
        // / HERO_REDESIGN_PALETTE). Defaults to PALETTE so every existing call is
        // byte-for-byte unchanged.
        const { flip = false, alpha = 1, tint = null, palette = PALETTE } = opts;
        const rows = matrix.length;
        const cols = matrix[0].length;

        ctx.save();
        ctx.imageSmoothingEnabled = false;
        if (alpha !== 1) ctx.globalAlpha *= alpha;

        for (let r = 0; r < rows; r++) {
            const row = matrix[r];
            for (let c = 0; c < cols; c++) {
                const key = row[c];
                if (key === '.' || key === ' ') continue;
                const color = tint || palette[key];
                if (!color) continue;
                const cc = flip ? (cols - 1 - c) : c;
                ctx.fillStyle = color;
                ctx.fillRect(originX + cc * pixelSize, originY + r * pixelSize, pixelSize, pixelSize);
            }
        }
        ctx.restore();
    }

    /**
     * Draw a frame centered horizontally on `centerX` with its FEET resting on
     * `bottomY` (so sprites stand on the ground regardless of grid height).
     * Origin is rounded to whole pixels to keep the art crisp.
     * @returns {{width:number,height:number,originX:number,originY:number}}
     */
    static drawSprite(ctx, frame, centerX, bottomY, opts = {}) {
        if (!frame || !frame.length) return null;
        const pixelSize = opts.pixelSize || 4;
        const cols = frame[0].length;
        const rows = frame.length;
        const wpx = cols * pixelSize;
        const hpx = rows * pixelSize;
        const originX = Math.round(centerX - wpx / 2);
        const originY = Math.round(bottomY - hpx);
        SpriteManager.drawMatrix(ctx, frame, originX, originY, pixelSize, opts);
        return { width: wpx, height: hpx, originX, originY };
    }

    static frameSize(frame, pixelSize) {
        return { width: frame[0].length * pixelSize, height: frame.length * pixelSize };
    }

    /** Soft contact shadow on the floor (call only while grounded). */
    static drawShadow(ctx, cx, groundY, width, opts = {}) {
        const { alpha = 0.3 } = opts;
        ctx.save();
        ctx.globalAlpha *= alpha;
        ctx.fillStyle = '#000000';
        ctx.beginPath();
        ctx.ellipse(cx, groundY, Math.max(6, width / 2), Math.max(3, width * 0.14), 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }

    /**
     * REQUIREMENT 2 + 4 — the Boss's procedural dark aura, upgraded to be far
     * larger and more majestic: a soft pool of darkness underfoot, a twin-layer
     * void haze, a slow-rotating crown of shadow tendrils, a dense ring of
     * swirling wisps, and rising embers. Driven by `time`, so it lives and
     * breathes. Draw it BEFORE the Boss sprite so the figure sits inside it.
     *
     * @param {object} opts { radius, time(ms), seed, intensity }
     */
    static drawAura(ctx, cx, cy, opts = {}) {
        const {
            radius = 70,
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            seed = 0,
            intensity = 1,
        } = opts;
        const t = time / 1000 + seed;
        const LITE = isLiteVfx();
        const PERF = isPerfVfx();

        ctx.save();
        ctx.translate(cx, cy);

        // 0) Pool of darkness pooled beneath the figure.
        ctx.save();
        ctx.globalAlpha = 0.30 * intensity;
        const pool = ctx.createRadialGradient(0, radius * 0.80, 2, 0, radius * 0.80, radius * 0.95);
        pool.addColorStop(0, 'rgba(10, 2, 16, 0.85)');
        pool.addColorStop(1, 'rgba(4, 1, 8, 0)');
        ctx.fillStyle = pool;
        ctx.beginPath();
        ctx.ellipse(0, radius * 0.82, radius * 0.98, radius * 0.34, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();

        // 1) Twin-layer void haze: inner violet glow over a broad dark cloud.
        const pulse = 0.85 + 0.18 * Math.sin(t * 1.6);
        const haze = ctx.createRadialGradient(0, 0, radius * 0.12, 0, 0, radius * pulse * 1.15);
        haze.addColorStop(0.00, `rgba(72, 20, 122, ${0.34 * intensity})`);
        haze.addColorStop(0.38, `rgba(40, 10, 70, ${0.26 * intensity})`);
        haze.addColorStop(0.72, `rgba(18, 5, 34, ${0.18 * intensity})`);
        haze.addColorStop(1.00, 'rgba(4, 1, 8, 0)');
        ctx.fillStyle = haze;
        ctx.beginPath();
        ctx.arc(0, 0, radius * pulse * 1.15, 0, Math.PI * 2);
        ctx.fill();

        // 2) Slow-rotating crown of shadow tendrils (the "majestic" silhouette).
        // Performance keeps the crown readable but thins it and drops the blur pass.
        const T = PERF ? 4 : (LITE ? 6 : 10);
        ctx.shadowBlur = PERF ? 0 : (LITE ? 8 : 16);
        for (let i = 0; i < T; i++) {
            const ang = t * 0.5 + (i * Math.PI * 2) / T;
            const len = radius * (0.95 + 0.18 * Math.sin(t * 1.3 + i));
            const x = Math.cos(ang) * len;
            const y = Math.sin(ang) * len * 0.92 - radius * 0.05;
            const a = 0.12 + 0.12 * (0.5 + 0.5 * Math.sin(t * 1.7 + i * 2.0));
            ctx.globalAlpha = a * intensity;
            ctx.fillStyle = 'rgba(26, 8, 48, 0.9)';
            ctx.shadowColor = 'rgba(80, 30, 150, 0.8)';
            ctx.beginPath();
            ctx.ellipse(x, y, radius * 0.16, radius * 0.07, ang, 0, Math.PI * 2);
            ctx.fill();
        }

        // 3) Dense ring of swirling shadow wisps (violet, with red sparks).
        const N = PERF ? 7 : (LITE ? 12 : 22);
        ctx.shadowBlur = LITE ? 0 : 10;
        for (let i = 0; i < N; i++) {
            const ang = t * (0.5 + 0.05 * i) + (i * Math.PI * 2) / N;
            const orbit = radius * (0.50 + 0.40 * Math.sin(t * 1.2 + i * 1.7));
            const x = Math.cos(ang) * orbit;
            const y = Math.sin(ang) * orbit * 0.80 - radius * 0.08;
            const s = 2.0 + 3.4 * ((i * 7) % 5) / 5;
            const red = i % 5 === 0;
            const a = 0.18 + 0.32 * (0.5 + 0.5 * Math.sin(t * 2.1 + i));
            ctx.globalAlpha = a * intensity;
            ctx.fillStyle = red ? 'rgba(255, 50, 50, 0.9)' : 'rgba(130, 65, 200, 0.9)';
            ctx.shadowColor = ctx.fillStyle;
            ctx.beginPath();
            ctx.arc(x, y, s, 0, Math.PI * 2);
            ctx.fill();
        }

        // 4) Embers drifting upward through the figure.
        const E = PERF ? 2 : (LITE ? 4 : 8);
        for (let i = 0; i < E; i++) {
            const phase = (t * 0.6 + i / E) % 1;            // 0..1 rise
            const x = Math.sin((i * 12.9 + t) * 1.3) * radius * 0.45;
            const y = radius * 0.55 - phase * radius * 1.35;  // bottom -> top
            const a = (1 - phase) * 0.55 * intensity;
            ctx.globalAlpha = a;
            ctx.fillStyle = i % 2 ? 'rgba(255, 70, 60, 0.95)' : 'rgba(160, 85, 230, 0.95)';
            ctx.shadowColor = ctx.fillStyle;
            ctx.shadowBlur = LITE ? 0 : 8;
            ctx.beginPath();
            ctx.arc(x, y, 1.6 + (1 - phase) * 1.8, 0, Math.PI * 2);
            ctx.fill();
        }

        ctx.restore();
    }

    /**
     * REQUIREMENT 3 (dash) — crimson "drill" aura. A tight blood-red halo
     * wrapping the curled Boss plus a spray of fast sparks spiralling around the
     * spin axis. Pair with drawSpeedStreaks() for the wind trail. Visual-only.
     *
     * @param {number} dir  +1 / -1 travel direction (the dash direction).
     * @param {object} opts { radius, time(ms), intensity }
     */
    static drawDashAura(ctx, cx, cy, dir = 1, opts = {}) {
        const { radius = 55, intensity = 1 } = opts;
        const E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a', DK = '#1c1d28';
        const PX = Math.max(2, Math.round(radius / 12));
        const d = dir >= 0 ? 1 : -1;
        ctx.save();
        ctx.translate(Math.round(cx), Math.round(cy));
        ctx.scale(d, 1);
        ctx.shadowBlur = 0;
        const baseGA = ctx.globalAlpha * Math.min(1.2, intensity);
        // sampler R2C0: 3 stepped dark afterimages (35/60/100%) trailing behind travel
        ctx.globalAlpha = baseGA * 0.35; ctx.fillStyle = DK; ctx.fillRect(-9 * PX, -7 * PX, 4 * PX, 14 * PX);
        ctx.globalAlpha = baseGA * 0.6;  ctx.fillStyle = DK; ctx.fillRect(-4 * PX, -7 * PX, 4 * PX, 14 * PX);
        ctx.globalAlpha = baseGA;        ctx.fillStyle = DK; ctx.fillRect(1 * PX, -8 * PX, 5 * PX, 16 * PX);
        ctx.fillStyle = E1; ctx.fillRect(3 * PX, -4 * PX, PX, 8 * PX);          // red core line
        // ember horizontal streaks (E0/E1/E2 at stepped rows)
        ctx.globalAlpha = baseGA * 0.8;
        ctx.fillStyle = E0; ctx.fillRect(-13 * PX, -8 * PX, 14 * PX, PX);
        ctx.fillStyle = E1; ctx.fillRect(-14 * PX, -4 * PX, 18 * PX, PX);
        ctx.fillStyle = E2; ctx.fillRect(-12 * PX, 0, 22 * PX, PX);
        ctx.fillStyle = E1; ctx.fillRect(-14 * PX, 4 * PX, 18 * PX, PX);
        ctx.fillStyle = E0; ctx.fillRect(-13 * PX, 8 * PX, 14 * PX, PX);
        ctx.globalAlpha = baseGA;
        // hot leading tip (E3/E2/E3 arrow)
        ctx.fillStyle = E3; ctx.fillRect(7 * PX, -1 * PX, 6 * PX, PX); ctx.fillRect(7 * PX, 1 * PX, 6 * PX, PX);
        ctx.fillStyle = E2; ctx.fillRect(5 * PX, 0, 8 * PX, PX);
        ctx.restore();
    }

    /**
     * REQUIREMENT 3 (dash) — wind / vacuum speed streaks left behind a fast
     * entity. `trail` is an array of {x, y} from OLDEST to NEWEST (the entity's
     * recent positions). Draws tapered motion lines that brighten toward the
     * head plus a few short wind dashes streaming off the back. Visual-only.
     *
     * @param {Array<{x:number,y:number}>} trail
     * @param {object} opts { time(ms), spread }  spread = fan half-height in px.
     */
    static drawSpeedStreaks(ctx, trail, opts = {}) {
        if (!trail || trail.length < 2) return;
        const { spread = 22 } = opts;
        const E1 = '#a8182a', E3 = '#ff5a4a';
        const n = trail.length, head = trail[n - 1], tail = trail[0];
        const dx = head.x - tail.x, dy = head.y - tail.y, len = Math.hypot(dx, dy) || 1;
        const nx = -dy / len, ny = dx / len;
        const PX = 2;
        ctx.save();
        ctx.shadowBlur = 0;
        const lanes = [-0.7, -0.35, 0, 0.35, 0.7];
        const baseGA = ctx.globalAlpha;
        for (let L = 0; L < lanes.length; L++) {
            const off = lanes[L] * spread, col = (L % 2) ? E3 : E1;
            for (let i = 1; i < n; i++) {
                ctx.globalAlpha = baseGA * (i / n) * 0.7;
                ctx.fillStyle = col;
                ctx.fillRect(Math.round(trail[i].x + nx * off) - PX, Math.round(trail[i].y + ny * off), PX * 2, PX);
            }
        }
        ctx.restore();
    }

    /**
     * REQUIREMENT 2 (void sword) — a small swirling glow that rides on the
     * Boss's blade so the weapon reads as bleeding dark energy. The caller
     * positions (x, y) on the blade; `dir` aims the swirl in the facing
     * direction. Visual-only.
     *
     * @param {object} opts { radius, time(ms), intensity }
     */
    static drawVoidEdge(ctx, x, y, dir = 1, opts = {}) {
        const { radius = 20, time = (typeof performance !== 'undefined' ? performance.now() : Date.now()), intensity = 1 } = opts;
        const PERF = isPerfVfx();
        const SMK = '#1a1420', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a';
        const PX = Math.max(2, Math.round(radius / 8));
        const frame = Math.floor(time / 80);
        const d = dir >= 0 ? 1 : -1;
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.globalAlpha *= Math.min(1, intensity);
        ctx.shadowBlur = 0;
        // small ember-void glint riding the blade: hot core + smoke rim + orbiting embers
        ctx.fillStyle = E3; ctx.fillRect(-PX, -PX, PX, PX);
        ctx.fillStyle = E2; ctx.fillRect(0, -PX, PX, PX); ctx.fillRect(-PX, 0, PX, PX);
        ctx.fillStyle = SMK; ctx.fillRect(0, 0, PX, PX);
        const pts = [[2, -1], [1, 2], [-2, 1]];
        for (let i = 0; i < (PERF ? 1 : 3); i++) {
            const [ox, oy] = pts[(i + frame) % 3];
            ctx.fillStyle = (i % 2) ? E1 : E3;
            ctx.fillRect(ox * PX * d, oy * PX, PX, PX);
        }
        ctx.restore();
    }

    /**
     * REQUIREMENT 3 - the Dark Flame projectile (Hit 3). A travelling ball of
     * violet hellfire: a dark-violet core, crackling crimson/amber tongues that
     * flicker forward along `dir`, and a smoky ember tail streaming behind it.
     * Procedural (gradients + particles), not a sprite matrix. Visual-only.
     *
     * @param {number} cx, cy  flame centre in world space.
     * @param {number} dir     +1 / -1 travel direction (default +1).
     * @param {object} opts     { time(ms), progress(0..1), width, height, intensity }
     */
    static drawDarkFlame(ctx, cx, cy, dir = 1, opts = {}) {
        const {
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            progress = 0, width = 64, height = 56, intensity = 1,
        } = opts;
        const t = time / 1000;
        const grow = Math.min(1, progress / 0.12);                       // quick spawn-in
        const fade = progress > 0.85 ? Math.max(0, 1 - (progress - 0.85) / 0.15) : 1; // burn-out
        const a = grow * fade * intensity;
        const R = height * 0.5;

        ctx.save();
        ctx.translate(cx, cy);

        // Smoky ember tail behind the flame (opposite the travel direction).
        for (let i = 0; i < 6; i++) {
            const back = (i + ((t * 4) % 1)) * (width * 0.16);
            const tx = -dir * (R * 0.4 + back);
            const ty = Math.sin(t * 6 + i) * R * 0.18;
            const ta = a * Math.max(0, 0.5 - back / (width * 1.1));
            ctx.globalAlpha = ta;
            ctx.fillStyle = i % 2 ? 'rgba(60, 20, 90, 0.8)' : 'rgba(120, 40, 40, 0.7)';
            ctx.beginPath();
            ctx.arc(tx, ty, R * (0.5 - i * 0.05), 0, Math.PI * 2);
            ctx.fill();
        }

        // Dark-violet core glow.
        ctx.globalAlpha = a;
        const core = ctx.createRadialGradient(0, 0, R * 0.12, 0, 0, R * 1.15);
        core.addColorStop(0.0, 'rgba(200, 130, 255, 0.95)');
        core.addColorStop(0.35, 'rgba(126, 63, 214, 0.85)');
        core.addColorStop(0.70, 'rgba(42, 20, 80, 0.55)');
        core.addColorStop(1.0, 'rgba(12, 4, 24, 0)');
        ctx.fillStyle = core;
        ctx.beginPath();
        ctx.arc(0, 0, R * 1.15, 0, Math.PI * 2);
        ctx.fill();

        // Crackling fire tongues licking forward + up (amber / crimson / violet).
        ctx.shadowBlur = 10;
        const N = 16;
        for (let i = 0; i < N; i++) {
            const flick = 0.5 + 0.5 * Math.sin(t * 14 + i * 1.7);
            const ang = (-Math.PI / 2) + (i / N - 0.5) * Math.PI * 1.1 + dir * 0.2;
            const len = R * (0.6 + 0.7 * flick);
            const fx = Math.cos(ang) * len * 0.7 + dir * R * 0.25 * flick;
            const fy = Math.sin(ang) * len;
            ctx.globalAlpha = a * (0.4 + 0.5 * flick);
            ctx.fillStyle = i % 3 === 0 ? 'rgba(255, 200, 110, 0.95)'
                          : i % 3 === 1 ? 'rgba(255, 70, 50, 0.95)'
                                        : 'rgba(190, 80, 255, 0.9)';
            ctx.shadowColor = ctx.fillStyle;
            ctx.beginPath();
            ctx.arc(fx, fy, 2 + 2.5 * flick, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    /**
     * REQUIREMENT 3 - the Explosive Finisher blast (Hit 4) AND the air-dive
     * landing shockwave. Both are the same detonation, so one function renders
     * both forms; pass `flat: true` for the ground-hugging shockwave variant.
     * Procedural (gradients + particles); visual-only.
     *
     *   default  : a massive spherical blast - white-hot heart, fiery
     *              orange/red/violet body, an expanding shock ring, flung shards
     *              and rising smoke. Draw it OVER the Boss for maximum impact.
     *   flat:true : a flattened ring of force racing outward across the floor
     *              with an inner glow + a kick of dust motes. Draw it UNDER the
     *              Boss, anchored at the ground line.
     *
     * @param {number} cx, cy  blast centre (spherical) / ground point (flat).
     * @param {object} opts     { time(ms), progress(0..1), radius, intensity, flat }
     */
    static drawExplosion(ctx, cx, cy, opts = {}) {
        const {
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            progress = 0, radius = 100, intensity = 1, flat = false,
        } = opts;
        const t = time / 1000;
        const ease = (p) => 1 - (1 - p) * (1 - p);
        const LITE = isLiteVfx();
        const PERF = isPerfVfx();

        // ---- Ground shockwave variant (air-dive landing) ----------------------
        if (flat) {
            const r = radius * (0.15 + 0.95 * ease(progress));
            const fade = Math.max(0, 1 - progress);
            const squash = 0.32; // vertical squash => a ground-hugging ring

            ctx.save();
            ctx.translate(cx, cy);

            // Inner ground glow.
            ctx.globalAlpha = fade * 0.5 * intensity;
            const glow = ctx.createRadialGradient(0, 0, 2, 0, 0, r);
            glow.addColorStop(0.0, 'rgba(190, 120, 255, 0.5)');
            glow.addColorStop(0.6, 'rgba(120, 40, 160, 0.22)');
            glow.addColorStop(1.0, 'rgba(20, 6, 30, 0)');
            ctx.fillStyle = glow;
            ctx.beginPath();
            ctx.ellipse(0, 0, r, r * squash, 0, 0, Math.PI * 2);
            ctx.fill();

            // The racing ring (bright violet crest + crimson under-ring).
            ctx.globalAlpha = fade * intensity;
            ctx.lineWidth = Math.max(2, r * 0.06 * (1 - progress * 0.6));
            ctx.shadowBlur = PERF ? 4 : (LITE ? 8 : 16);
            ctx.shadowColor = 'rgba(150, 80, 255, 0.9)';
            ctx.strokeStyle = 'rgba(230, 200, 255, 0.95)';
            ctx.beginPath();
            ctx.ellipse(0, 0, r, r * squash, 0, 0, Math.PI * 2);
            ctx.stroke();

            ctx.lineWidth = Math.max(1, r * 0.03);
            ctx.strokeStyle = 'rgba(255, 70, 90, 0.7)';
            ctx.shadowColor = 'rgba(255, 60, 70, 0.8)';
            ctx.beginPath();
            ctx.ellipse(0, 0, r * 0.82, r * squash * 0.82, 0, 0, Math.PI * 2);
            ctx.stroke();

            // Dust motes kicked up around the ring crest.
            ctx.shadowBlur = LITE ? 0 : 6;
            const Nd = PERF ? 4 : (LITE ? 7 : 14);
            for (let i = 0; i < Nd; i++) {
                const ang = (i / Nd) * Math.PI * 2;
                const dx = Math.cos(ang) * r;
                const dy = Math.sin(ang) * r * squash - progress * 18; // lift as it travels
                ctx.globalAlpha = fade * (0.4 + 0.4 * Math.sin(t * 12 + i)) * intensity;
                ctx.fillStyle = i % 2 ? 'rgba(200, 160, 255, 0.85)' : 'rgba(150, 90, 210, 0.8)';
                ctx.shadowColor = ctx.fillStyle;
                ctx.beginPath();
                ctx.arc(dx, dy, 1.6 + (i % 3), 0, Math.PI * 2);
                ctx.fill();
            }
            ctx.restore();
            return;
        }

        // ---- Spherical blast variant (finisher) -------------------------------
        const r = radius * (0.25 + 0.85 * ease(progress));
        const fade = progress < 0.6 ? 1 : Math.max(0, 1 - (progress - 0.6) / 0.4);

        ctx.save();
        ctx.translate(cx, cy);

        // Fiery body.
        ctx.globalAlpha = fade * intensity;
        const body = ctx.createRadialGradient(0, 0, r * 0.05, 0, 0, r);
        body.addColorStop(0.00, 'rgba(255, 255, 240, 0.98)');
        body.addColorStop(0.18, 'rgba(255, 220, 130, 0.95)');
        body.addColorStop(0.42, 'rgba(255, 110, 50, 0.9)');
        body.addColorStop(0.68, 'rgba(190, 40, 60, 0.7)');
        body.addColorStop(0.86, 'rgba(110, 40, 160, 0.45)');
        body.addColorStop(1.00, 'rgba(20, 6, 30, 0)');
        ctx.fillStyle = body;
        ctx.beginPath();
        ctx.arc(0, 0, r, 0, Math.PI * 2);
        ctx.fill();

        // Expanding shock ring.
        ctx.globalAlpha = fade * 0.8 * intensity;
        ctx.lineWidth = Math.max(1.5, r * 0.05 * (1 - progress));
        ctx.strokeStyle = 'rgba(255, 230, 180, 0.9)';
        ctx.shadowBlur = PERF ? 5 : (LITE ? 9 : 18);
        ctx.shadowColor = 'rgba(255, 140, 60, 0.9)';
        ctx.beginPath();
        ctx.arc(0, 0, r * (0.85 + 0.2 * progress), 0, Math.PI * 2);
        ctx.stroke();

        // Radial shards flung outward.
        ctx.shadowBlur = LITE ? 0 : 10;
        const Ns = PERF ? 6 : (LITE ? 10 : 20);
        for (let i = 0; i < Ns; i++) {
            const ang = (i / Ns) * Math.PI * 2 + i * 0.3;
            const dist = r * (0.6 + 0.5 * ((i * 7) % 5) / 5);
            const sx = Math.cos(ang) * dist;
            const sy = Math.sin(ang) * dist;
            ctx.globalAlpha = fade * (0.5 + 0.4 * Math.sin(t * 10 + i)) * intensity;
            ctx.fillStyle = i % 2 ? 'rgba(255, 180, 90, 0.95)' : 'rgba(255, 80, 60, 0.95)';
            ctx.shadowColor = ctx.fillStyle;
            ctx.beginPath();
            ctx.arc(sx, sy, 2 + (i % 3) * 1.6, 0, Math.PI * 2);
            ctx.fill();
        }

        // Rising smoke puffs as it dissipates.
        for (let i = 0; i < (PERF ? 2 : (LITE ? 3 : 6)); i++) {
            const rise = progress * r * 0.9;
            const px = Math.cos(i * 1.7) * r * 0.4;
            const py = -rise + Math.sin(i * 2.1) * r * 0.1;
            ctx.globalAlpha = fade * 0.3 * intensity;
            ctx.fillStyle = 'rgba(40, 20, 50, 0.7)';
            ctx.shadowBlur = 0;
            ctx.beginPath();
            ctx.arc(px, py, r * (0.18 + 0.05 * i) * progress, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();
    }

    /**
     * Convenience alias: the air-dive landing shockwave is simply the explosion
     * rendered in its flattened ground mode. Kept so call sites (Player.js) read
     * by intent; it adds no new logic - just forwards to drawExplosion().
     */
    // Boss AERIAL-SLAM ground impact = the approved 1.png landing dust (sampler R2C3),
    // brought to slam scale: several chunky stone-dust clusters that burst from the
    // centre and settle outward across the impact width, staggered so it reads as one
    // wide ground impact. 100% pixel-art (delegates to the exact R2C3 drawLandingDust).
    // Cosmetic only — the shockwave hitbox / Fear-Strike gameplay is untouched.
    static drawShockwave(ctx, gx, gy, opts = {}) {
        const { progress = 0, radius = 110 } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        // [offsetX (fraction of radius), start-delay]: centre first, flanks spread out.
        // px=2 keeps the exact 1.png chunkiness; wide spacing reads as distinct puffs.
        let clusters = [
            [0, 0.00], [-0.55, 0.08], [0.55, 0.05], [-1.0, 0.17], [1.0, 0.13],
        ];
        if (isPerfVfx()) clusters = clusters.slice(0, 3);
        else if (isLiteVfx()) clusters = clusters.slice(0, 4);
        for (const [fx, delay] of clusters) {
            if (p <= delay) continue;
            const cp = (p - delay) / (1 - delay);              // remap so this cluster runs 0..1
            SpriteManager.drawLandingDust(ctx, Math.round(gx + fx * radius), gy, { progress: cp, px: 2 });
        }
    }

    // ===================================================================
    //  HERO "COLD SANCTITY" VFX — TRUE PIXEL ART
    //  Source of truth: the approved sampler tools/redesign/vfx_gen.js (1.png).
    //  Everything below is drawn as discrete hard-edged PX blocks (fillRect ONLY:
    //  no shadowBlur, no bezier curves, no soft alpha washes) so it reads as
    //  authentic pixel art exactly like the sheet. Ramp:
    //    core #eaf6ff · body #b8ecff · edge #7fd4ff · rim #4a7a9e · gold tip #c9962e
    //  Grammar: gather -> crisp crescent/strike -> shard + sparkle dissolve.
    // ===================================================================

    /**
     * The Hero's HOLY LIGHT WAVE — a crisp PIXEL-ART crescent of focused light
     * (approved "cold sanctity" sheet). Built entirely from discrete PX blocks:
     * white core #eaf6ff -> body #b8ecff -> cold edge #7fd4ff -> rim #4a7a9e, tips
     * tapering to single pixels. NO blur, NO curves, NO glow-painted arc.
     *
     * Lifecycle from opts.life (0..1 = the projectile's existing lifeProgress,
     * read-only): gather (converging motes) -> crescent (wave body, 1px marching
     * edge-shimmer) -> dissolve (breaks into drifting shards + sparkles). Keeps the
     * diagonal / vertical / X identities, size, life, hitbox and timing.
     *
     * waveType: 1 diagonal · 2 vertical · 3 X-cross.  facing +1/-1 mirrors it.
     */
    static drawLightWave(ctx, x, y, waveType = 1, facing = 1, opts = {}) {
        const { alpha = 1, size = 140, life = 0.5 } = opts;
        if (alpha <= 0 || size <= 0) return;
        const dir = facing >= 0 ? 1 : -1;
        const PX = Math.max(2, Math.min(6, Math.round(size / 30)));   // sampler crescent ~29px tall -> ~size
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.globalAlpha *= alpha;
        ctx.shadowBlur = 0;                                            // hard pixels only
        // Direct port of the approved sampler phases (tools/redesign/vfx_gen.js R1):
        // gather cell -> crescent cell -> dissolve cell (stepped, no soft tween).
        if (life < 0.07) {
            SpriteManager._paintCells(ctx, SpriteManager._heroGatherCells(), PX, dir, false);
        } else if (life > 0.78) {
            SpriteManager._paintCells(ctx, SpriteManager._heroDissolveCells(), PX, dir, false);
        } else {
            SpriteManager._paintCells(ctx, SpriteManager._heroCrescentCells(dir, waveType === 3), PX, 1, false);
        }
        ctx.restore();
    }

    // ---- EXACT ports of the approved 1.png hero cells (tools/redesign/vfx_gen.js) ----
    // Hero light ramp: L0 #4a7a9e (back edge) · L1 #7fd4ff (inner) · L2 #b8ecff (body)
    // · L3 #eaf6ff (white core) · GLD #c9962e.  Every cell below is the sheet's exact
    // pixel layout, returned centred so it can be scaled by PX and mirrored by travel.

    // The sheet crescent() ported verbatim. `travelDir` orients the convex/white-core
    // edge toward travel: travelDir>=0 -> bulge right (sheet dir=-1), else bulge left
    // (sheet dir=+1). `doubleEdge` = the finisher's extra outer edge.
    static _heroCrescentCells(travelDir, doubleEdge) {
        const L0 = '#4a7a9e', L1 = '#7fd4ff', L2 = '#b8ecff', L3 = '#eaf6ff';
        const dir = travelDir >= 0 ? -1 : 1;
        const raw = [];
        for (let y = 6; y <= 34; y++) {
            const s = Math.sin((y - 6) / 28 * Math.PI);
            const xo = 20 - dir * Math.round(14 * s);
            const wdt = Math.max(1, Math.round(1 + 4 * s));
            if (dir < 0) {
                raw.push([xo - 1, y, L0]);
                for (let k = 0; k < Math.max(1, wdt - 1); k++) raw.push([xo + k, y, L2]);
                raw.push([xo + wdt - 1, y, L1]);
                if (y >= 16 && y <= 24) raw.push([xo + wdt, y, L3]);
                if (doubleEdge) raw.push([xo - 2, y, L0]);
            } else {
                raw.push([xo + 1, y, L0]);
                for (let k = 0; k < Math.max(1, wdt - 1); k++) raw.push([xo - wdt + 2 + k, y, L2]);
                raw.push([xo - wdt + 1, y, L1]);
                if (y >= 16 && y <= 24) raw.push([xo - wdt, y, L3]);
                if (doubleEdge) raw.push([xo + 2, y, L0]);
            }
        }
        let minx = 1e9, maxx = -1e9, miny = 1e9, maxy = -1e9;
        for (const [px, py] of raw) { if (px < minx) minx = px; if (px > maxx) maxx = px; if (py < miny) miny = py; if (py > maxy) maxy = py; }
        const cx = (minx + maxx) >> 1, cy = (miny + maxy) >> 1;
        return raw.map(([px, py, c]) => ({ gx: px - cx, gy: py - cy, color: c }));
    }

    // Sheet R1C0 GATHER (verbatim): 2x2 white core, 4 icy corners, 6 pale + 4 steel motes.
    static _heroGatherCells() {
        const L0 = '#4a7a9e', L1 = '#7fd4ff', L2 = '#b8ecff', L3 = '#eaf6ff';
        const c = [], push = (x, y, col) => c.push({ gx: x - 20, gy: y - 20, color: col });
        push(19, 19, L3); push(20, 19, L3); push(19, 20, L3); push(20, 20, L3);
        push(18, 18, L1); push(21, 18, L1); push(18, 21, L1); push(21, 21, L1);
        [[13, 13], [26, 12], [12, 26], [27, 27], [20, 10], [20, 30]].forEach(([x, y]) => push(x, y, L2));
        [[15, 15], [24, 14], [14, 24], [25, 25]].forEach(([x, y]) => push(x, y, L0));
        return c;
    }

    // Sheet R1C2 DISSOLVE (verbatim): vertical shard fragments + scattered motes.
    static _heroDissolveCells() {
        const L0 = '#4a7a9e', L1 = '#7fd4ff', L2 = '#b8ecff';
        const c = [], cx = 22, cy = 20;
        const seg = (x, y, h, col) => { for (let k = 0; k < h; k++) c.push({ gx: x - cx, gy: y + k - cy, color: col }); };
        seg(26, 9, 4, L2); seg(28, 14, 3, L1); seg(30, 22, 4, L2); seg(28, 27, 3, L1); seg(26, 31, 2, L0);
        [[22, 12], [20, 18], [23, 24], [21, 30], [16, 20], [25, 16]].forEach(([x, y]) => c.push({ gx: x - cx, gy: y - cy, color: L1 }));
        [[18, 14], [17, 26], [24, 20]].forEach(([x, y]) => c.push({ gx: x - cx, gy: y - cy, color: L0 }));
        c.push({ gx: 14 - cx, gy: 19 - cy, color: L2 });
        return c;
    }

    // Paint a centred cell list as hard PX blocks. `mir` mirrors X by travel; `swap`
    // rotates 90deg (pogo down-strike). Grid-snapped fillRect only — no blur/curves.
    static _paintCells(ctx, cells, PX, mir = 1, swap = false) {
        const baseGA = ctx.globalAlpha;
        for (const { gx, gy, color, a } of cells) {
            const ax = swap ? gy : gx * mir;
            const ay = swap ? gx : gy;
            if (a != null) ctx.globalAlpha = baseGA * a;
            ctx.fillStyle = color;
            ctx.fillRect(ax * PX, ay * PX, PX, PX);
            if (a != null) ctx.globalAlpha = baseGA;
        }
    }

    // ===================================================================
    //  BOSS "EMBER-VOID" VFX — TRUE PIXEL ART (sampler vfx_gen.js row 0/2)
    //  Ember ramp: SMK #1a1420 · UMB #14101c · E0 #6e0f1c · E1 #a8182a
    //             · E2 #e0263a · E3 #ff5a4a.  Hard fillRect blocks only.
    // ===================================================================

    // Sampler crescent() with the boss layers [SMK, E1, E2, E3] (smoke outer edge,
    // ember body, bright inner, hot molten core). Centred; travelDir orients the bulge.
    static _bossCrescentCells(travelDir, doubleEdge) {
        const SMK = '#1a1420', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a';
        const dir = travelDir >= 0 ? -1 : 1;
        const raw = [];
        for (let y = 6; y <= 34; y++) {
            const s = Math.sin((y - 6) / 28 * Math.PI);
            const xo = 20 - dir * Math.round(14 * s);
            const wdt = Math.max(1, Math.round(1 + 4 * s));
            if (dir < 0) {
                raw.push([xo - 1, y, SMK]);
                for (let k = 0; k < Math.max(1, wdt - 1); k++) raw.push([xo + k, y, E1]);
                raw.push([xo + wdt - 1, y, E2]);
                if (y >= 16 && y <= 24) raw.push([xo + wdt, y, E3]);
                if (doubleEdge) raw.push([xo - 2, y, SMK]);
            } else {
                raw.push([xo + 1, y, SMK]);
                for (let k = 0; k < Math.max(1, wdt - 1); k++) raw.push([xo - wdt + 2 + k, y, E1]);
                raw.push([xo - wdt + 1, y, E2]);
                if (y >= 16 && y <= 24) raw.push([xo - wdt, y, E3]);
                if (doubleEdge) raw.push([xo + 2, y, SMK]);
            }
        }
        let minx = 1e9, maxx = -1e9, miny = 1e9, maxy = -1e9;
        for (const [px, py] of raw) { if (px < minx) minx = px; if (px > maxx) maxx = px; if (py < miny) miny = py; if (py > maxy) maxy = py; }
        const cx = (minx + maxx) >> 1, cy = (miny + maxy) >> 1;
        return raw.map(([px, py, c]) => ({ gx: px - cx, gy: py - cy, color: c }));
    }

    // Sampler R0C0 boss-slash ANTICIPATION (verbatim): dark ember verticals + E1 blade
    // + E1/E0 pairs + faint core = ember fragments gathering before the strike.
    static _bossGatherCells() {
        const E0 = '#6e0f1c', E1 = '#a8182a';
        const c = [], cx = 16, cy = 20;
        const seg = (x, y, h, col, a) => { for (let k = 0; k < h; k++) c.push({ gx: x - cx, gy: y + k - cy, color: col, a }); };
        [[12, 10], [8, 16], [7, 20], [8, 24], [12, 30]].forEach(([x, y]) => seg(x, y, 2, E0));
        seg(9, 18, 4, E1);
        [[24, 12], [26, 20], [24, 28]].forEach(([x, y]) => { c.push({ gx: x - cx, gy: y - cy, color: E1 }); c.push({ gx: x + 2 - cx, gy: y - cy, color: E0 }); });
        for (let dx = 0; dx < 2; dx++) for (let dy = 0; dy < 2; dy++) c.push({ gx: 16 + dx - cx, gy: 19 + dy - cy, color: E0, a: 0.6 });
        return c;
    }

    // Sampler R0C2 boss-slash FADE (verbatim): ember shard fragments + smoke puffs.
    static _bossFadeCells() {
        const E0 = '#6e0f1c', E1 = '#a8182a', SMK = '#1a1420';
        const c = [], cx = 14, cy = 20;
        const seg = (x, y, h, col, a) => { for (let k = 0; k < h; k++) c.push({ gx: x - cx, gy: y + k - cy, color: col, a }); };
        seg(12, 8, 3, E1); seg(10, 12, 3, E0); seg(8, 22, 4, E1); seg(10, 27, 3, E0); seg(13, 31, 2, E0);
        const puff = (x, y, a) => { for (let dx = 0; dx < 2; dx++) for (let dy = 0; dy < 2; dy++) c.push({ gx: x + dx - cx, gy: y + dy - cy, color: SMK, a }); };
        puff(6, 14); puff(5, 26); puff(11, 18, 0.7);
        [[16, 10], [18, 16], [15, 22], [18, 28], [16, 33], [22, 20]].forEach(([x, y]) => c.push({ gx: x - cx, gy: y - cy, color: E0 }));
        c.push({ gx: 20 - cx, gy: 13 - cy, color: E1 }); c.push({ gx: 21 - cx, gy: 26 - cy, color: E1 });
        return c;
    }

    /**
     * drawBossSlash — the Boss's sword crescent, built from the approved sheet boss
     * slash (R0C0/C1/C2). `progress` (0..1 over the existing active frames) steps
     * gather -> smoke-rimmed ember crescent -> shard fade. Cosmetic only.
     */
    static drawBossSlash(ctx, x, y, dir = 1, progress = 0, opts = {}) {
        const { reach = 30, size = 150, heavy = false } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1) return;
        const travelDir = dir >= 0 ? 1 : -1;
        const PX = Math.max(2, Math.min(6, Math.round(size / 30)));
        ctx.save();
        ctx.translate(Math.round(x + travelDir * reach * 0.4), Math.round(y));
        ctx.shadowBlur = 0;
        if (p < 0.25) SpriteManager._paintCells(ctx, SpriteManager._bossGatherCells(), PX, travelDir);
        else if (p > 0.72) SpriteManager._paintCells(ctx, SpriteManager._bossFadeCells(), PX, travelDir);
        else SpriteManager._paintCells(ctx, SpriteManager._bossCrescentCells(travelDir, heavy), PX, 1);
        ctx.restore();
    }

    /**
     * drawHolySlash — the Hero's melee sword-arc, built from the SAME approved sheet
     * crescent (drawLightWave family). `progress` (0..1 over the existing active frames)
     * steps gather -> crescent -> dissolve. Finisher = the sheet's double edge; pogo
     * passes rot = PI/2 so the crescent is rotated 90deg down. Cosmetic only.
     */
    static drawHolySlash(ctx, x, y, dir = 1, progress = 0, opts = {}) {
        const { reach = 26, size = 46, heavy = false, rot = null } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1) return;
        const travelDir = dir >= 0 ? 1 : -1;
        const PX = Math.max(2, Math.min(5, Math.round(size / 30)));
        const swap = rot === Math.PI / 2;                             // pogo = rotate 90deg down
        ctx.save();
        ctx.translate(Math.round(x + travelDir * reach * 0.4), Math.round(y));
        ctx.shadowBlur = 0;
        if (p < 0.25 && !swap) {
            SpriteManager._paintCells(ctx, SpriteManager._heroGatherCells(), PX, travelDir, false);
        } else if (p > 0.72 && !swap) {
            SpriteManager._paintCells(ctx, SpriteManager._heroDissolveCells(), PX, travelDir, false);
        } else {
            SpriteManager._paintCells(ctx, SpriteManager._heroCrescentCells(travelDir, heavy), PX, 1, swap);
        }
        ctx.restore();
    }

    /**
     * drawParryRing — EXACT port of the approved sheet parry ring (R1C3): a solid icy
     * ring (#7fd4ff), four white cardinal highlights (#eaf6ff) at N/S/W/E, four diagonal
     * sparks each ending in a single gold pixel (#b8ecff spark -> #c9962e tip), and a
     * faint inner ring. `stance` = faint inner-ring pulse only; `progress` expands the
     * counter ring. Radius/anchor only position it — hitbox/i-frames unchanged.
     */
    static drawParryRing(ctx, x, y, opts = {}) {
        const { radius = 34, progress = 0, stance = false,
                time = (typeof performance !== 'undefined' ? performance.now() : Date.now()) } = opts;
        const PERF = isPerfVfx(), LITE = isLiteVfx();
        const L1 = '#7fd4ff', L2 = '#b8ecff', L3 = '#eaf6ff', GLD = '#c9962e';
        const PX = PERF ? 3 : 2;
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.shadowBlur = 0;
        const block = (dx, dy, col) => { ctx.fillStyle = col; ctx.fillRect(Math.round(dx / PX) * PX, Math.round(dy / PX) * PX, PX, PX); };
        const ring = (R, col) => {
            const n = Math.max(12, Math.round(2 * Math.PI * R / PX));
            for (let a = 0; a < n; a++) { const th = a / n * 2 * Math.PI; block(Math.cos(th) * R, Math.sin(th) * R, col); }
        };
        if (stance) {
            const R = radius * 0.42;
            ctx.globalAlpha *= (Math.floor(time / 120) % 2 === 0) ? 0.55 : 0.32;
            ring(R, L1);
            ctx.restore();
            return;
        }
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        const R = radius * (0.45 + 0.55 * p);
        ring(R, L1);                                                   // main icy ring
        for (const [ux, uy] of [[0, -1], [0, 1], [-1, 0], [1, 0]]) block(ux * R, uy * R, L3); // white cardinals
        if (!PERF) {
            for (const [sx, sy] of [[-1, -1], [1, -1], [-1, 1], [1, 1]]) {   // diagonal sparks + gold tips
                const bx = Math.round(sx * R * Math.SQRT1_2 / PX), by = Math.round(sy * R * Math.SQRT1_2 / PX);
                ctx.fillStyle = L2; ctx.fillRect((bx + sx * 2) * PX, (by + sy * 2) * PX, PX, PX);
                ctx.fillStyle = GLD; ctx.fillRect((bx + sx * 3) * PX, (by + sy * 3) * PX, PX, PX);
            }
            if (!LITE) { ctx.save(); ctx.globalAlpha *= 0.4; ring(R * 0.45, L1); ctx.restore(); } // faint inner ring
        }
        ctx.restore();
    }

    /**
     * drawHeroDashStreaks — silver-blue dash (sampler R2C1): stepped sprite
     * afterimages (35% / 60%), a steel motion-streak bundle (#7c88a0 / #aeb9cc)
     * with one cape-dark line (#141c30) on top, and a crisp icy leading tip
     * (#b8ecff / #eaf6ff). All hard pixels. Cosmetic — dash speed/duration unchanged.
     */
    static drawHeroDashStreaks(ctx, x, y, dir = 1, opts = {}) {
        const { frame = null, pixelSize = 2, flip = false, palette = null, feetY = y } = opts;
        const LITE = isLiteVfx(), PERF = isPerfVfx();
        const d = dir >= 0 ? 1 : -1;
        if (frame) {                                          // stepped pixel-sprite afterimages
            const steps = PERF ? [[10, 0.35]] : (LITE ? [[9, 0.35], [16, 0.22]] : [[8, 0.35], [15, 0.55]]);
            for (const [off, a] of steps) {
                SpriteManager.drawSprite(ctx, frame, x - d * off, feetY, { pixelSize, flip, palette, tint: '#8fa9c8', alpha: a });
            }
        }
        ctx.save();
        ctx.shadowBlur = 0;
        const PX = 2, len = 22;
        const streaks = PERF ? [[-2, '#aeb9cc']]
                     : (LITE ? [[-6, '#7c88a0'], [2, '#aeb9cc']]
                             : [[-8, '#141c30'], [-3, '#7c88a0'], [3, '#aeb9cc'], [7, '#7c88a0']]);
        for (const [dy, col] of streaks) {                    // thin solid steel streak lines
            ctx.fillStyle = col;
            ctx.fillRect(x - d * len, y + dy, len - 4, PX);
        }
        // crisp icy leading tip (chevron of pixel blocks)
        ctx.fillStyle = '#b8ecff';
        ctx.fillRect(x + d * 8, y - 4, PX, PX); ctx.fillRect(x + d * 11, y - 2, PX, PX);
        ctx.fillRect(x + d * 12, y, PX, PX);
        ctx.fillRect(x + d * 11, y + 2, PX, PX); ctx.fillRect(x + d * 8, y + 4, PX, PX);
        ctx.fillStyle = '#eaf6ff'; ctx.fillRect(x + d * 10, y, PX, PX);
        ctx.restore();
    }

    /**
     * drawHeroTakeoffMotes — small rising #b8ecff pixel motes at the feet on a jump
     * takeoff (`progress` 0..1 rises + fades them). Discrete blocks, subtle.
     */
    static drawHeroTakeoffMotes(ctx, x, feetY, opts = {}) {
        const p = (opts.progress < 0 ? 0 : opts.progress > 1 ? 1 : opts.progress) || 0;
        const PX = 2;
        ctx.save();
        ctx.shadowBlur = 0;
        ctx.globalAlpha *= (1 - p);
        ctx.fillStyle = '#b8ecff';
        const rise = Math.round(p * 14);
        for (const [dx, ph] of [[-5, 0], [5, 3], [-2, 6], [3, 2]]) {
            if ((Math.round(p * 10) + dx) % 2 !== 0) continue;
            ctx.fillRect(x + dx * PX, feetY - 2 - rise - ph, PX, PX);
        }
        ctx.restore();
    }

    /**
     * drawLandingDust — neutral ground-contact puff in the hall's warm stone tones
     * (sampler R2C3): symmetric #6b5c48/#4a3f33 puffs with #b3a184 highlights, a
     * tiny chevron, and two rising #8d7b60 motes. `progress` fades + settles it.
     * All hard pixels. Cosmetic.
     */
    // EXACT port of the approved sampler landing dust (vfx_gen.js R2C3): a stone
    // ground line + shadow, two symmetric DU1 dust puffs with DU3 highlights and
    // DU0 roots, a little centre spray, and two rising motes. `progress` (0..1)
    // fades it out and lifts the motes; the silhouette stays the sheet's exactly.
    static drawLandingDust(ctx, x, groundY, opts = {}) {
        const { progress = 0, px = 2 } = opts;
        const PERF = isPerfVfx(), LITE = isLiteVfx();
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        const DU0 = '#4a3f33', DU1 = '#6b5c48', DU2 = '#8d7b60', DU3 = '#b3a184';
        const PX = px;
        const rise = Math.round(p * 2.5 * PX);
        ctx.save();
        ctx.shadowBlur = 0;
        const baseGA = ctx.globalAlpha * (1 - p);                       // fade over the dust's life
        // Paint a sampler cell (cellX,cellY,w,h) relative to centre col 20 / ground row 30.
        const cell = (cx, cy, w, h, col, al, lift) => {
            ctx.globalAlpha = baseGA * (al == null ? 1 : al);
            ctx.fillStyle = col;
            ctx.fillRect(x + (cx - 20) * PX, groundY + (cy - 30) * PX - (lift ? rise : 0), w * PX, h * PX);
        };
        cell(4, 30, 32, 1, DU2);                                        // ground line
        cell(4, 31, 32, 3, DU0, 0.5);                                  // ground shadow
        cell(10, 26, 3, 3, DU1); cell(12, 25, 1, 1, DU3); cell(6, 27, 2, 2, DU0);   // left puff
        cell(27, 26, 3, 3, DU1); cell(27, 25, 1, 1, DU3); cell(32, 27, 2, 2, DU0);  // right puff
        cell(17, 24, 2, 1, DU3); cell(21, 24, 2, 1, DU3);              // centre spray
        cell(16, 22, 1, 1, DU2); cell(23, 22, 1, 1, DU2);
        if (!PERF) { cell(8, 24, 2, 2, DU1, 0.7); cell(30, 24, 2, 2, DU1, 0.7); }   // faint puff caps
        if (!LITE) { cell(14, 19, 1, 1, DU2, 0.7, true); cell(25, 19, 1, 1, DU2, 0.7, true); } // rising motes
        ctx.restore();
    }

    /**
     * Glorious lingering golden sparkle burst for the parry COUNTER-ATTACK.
     * A radiant bloom, an expanding shock ring, long radiating rays and a swarm
     * of twinkling motes. Self-positions at (x, y) and self-animates, so it can
     * simply be called every frame the counter is live.
     *
     * @param {object} [opts] { time(ms), intensity, radius, progress }
     *        progress 0..1 (optional) drives the ring expansion + fade; if
     *        omitted the burst breathes on a gentle loop (good for a hold).
     */
    static drawParrySparkles(ctx, x, y, opts = {}) {
        const {
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            intensity = 1,
            radius = 90,
            progress = null,
        } = opts;
        const t = time / 1000;

        const grow = progress != null ? progress : (0.5 + 0.5 * Math.sin(t * 3));
        const A = intensity * (progress != null ? Math.max(0, 1 - progress) : 1);
        if (A <= 0) return;

        ctx.save();
        ctx.translate(x, y);
        ctx.lineCap = 'round';

        // 0) Golden bloom core.
        const bloom = ctx.createRadialGradient(0, 0, 2, 0, 0, radius * 0.9);
        bloom.addColorStop(0.00, `rgba(255, 250, 210, ${0.55 * A})`);
        bloom.addColorStop(0.35, `rgba(255, 215, 110, ${0.32 * A})`);
        bloom.addColorStop(1.00, 'rgba(255, 190, 50, 0)');
        ctx.fillStyle = bloom;
        ctx.beginPath();
        ctx.arc(0, 0, radius * 0.9, 0, Math.PI * 2);
        ctx.fill();

        // 1) Expanding shock ring.
        ctx.globalAlpha = 0.80 * A;
        ctx.lineWidth = 4;
        ctx.strokeStyle = 'rgba(255, 230, 140, 0.9)';
        ctx.shadowBlur = 22;
        ctx.shadowColor = 'rgba(255, 200, 60, 1)';
        ctx.beginPath();
        ctx.arc(0, 0, radius * (0.35 + 0.55 * grow), 0, Math.PI * 2);
        ctx.stroke();

        // 2) Long radiating rays (alternating long/short), slowly spinning.
        const RAYS = 12;
        for (let i = 0; i < RAYS; i++) {
            const ang = t * 0.8 + (i * Math.PI * 2) / RAYS;
            const long = i % 2 === 0;
            const r0 = radius * 0.18;
            const r1 = radius * (long ? (0.85 + 0.12 * Math.sin(t * 4 + i)) : 0.5);
            const cos = Math.cos(ang), sin = Math.sin(ang);
            ctx.globalAlpha = (long ? 0.85 : 0.5) * A * (0.6 + 0.4 * Math.sin(t * 5 + i));
            ctx.lineWidth = long ? 2.4 : 1.4;
            ctx.strokeStyle = 'rgba(255, 240, 170, 0.95)';
            ctx.shadowBlur = 10;
            ctx.shadowColor = 'rgba(255, 210, 90, 0.95)';
            ctx.beginPath();
            ctx.moveTo(cos * r0, sin * r0);
            ctx.lineTo(cos * r1, sin * r1);
            ctx.stroke();
        }

        // 3) Twinkling motes scattered through the bloom (golden-angle spread).
        const M = 18;
        ctx.shadowBlur = 8;
        for (let i = 0; i < M; i++) {
            const ang = i * 2.399963 + t * (0.6 + 0.04 * i);
            const rad = radius * (0.15 + 0.70 * ((i * 7) % 11) / 11);
            const px = Math.cos(ang) * rad;
            const py = Math.sin(ang) * rad * 0.92;
            const tw = 0.5 + 0.5 * Math.sin(t * 7 + i * 1.7);
            ctx.globalAlpha = tw * 0.9 * A;
            ctx.fillStyle = i % 3 === 0 ? 'rgba(255, 255, 240, 0.95)' : 'rgba(255, 215, 110, 0.95)';
            ctx.shadowColor = ctx.fillStyle;
            ctx.beginPath();
            ctx.arc(px, py, 1.3 + 1.6 * tw, 0, Math.PI * 2);
            ctx.fill();
        }

        ctx.restore();
    }

    /**
     * SCREEN-SPACE fear effect — call while the Hero is under the 4s Fear Status.
     * Walls of roaring black-and-crimson fire climb the LEFT and RIGHT edges only
     * (top & bottom are intentionally clear now). Each wall is a stack of
     * overlapping sine-driven flame curtains — deep-black roots bleeding up into
     * bright crimson — plus flickering bezier tongues that lick inward and rising
     * embers. Draw in SCREEN space, after the camera transform is restored.
     *
     * @param {number} canvasWidth
     * @param {number} canvasHeight
     * @param {object} [opts] { time(ms), intensity }  intensity (0..1) fades it in/out.
     */
    static drawFearScreenEffect(ctx, canvasWidth, canvasHeight, opts = {}) {
        const {
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            intensity = 1,
        } = opts;
        const A = intensity;
        if (A <= 0) return;
        const t = time / 1000;
        const W = canvasWidth, H = canvasHeight;
        if (W <= 0 || H <= 0) return; // nothing to paint on a zero-size canvas

        // How far the fire reaches in from each side (capped so wide monitors
        // don't swallow the play area).
        const band = Math.min(W * 0.24, 280);

        // Layered curtains, back (darkest) -> front (brightest lick). `reach` is a
        // fraction of `band`; amp/freq/speed shape the sine sway; `stops` paint the
        // black -> crimson -> red heat ramp. Each stop is [offset, "r,g,b", alpha].
        const LAYERS = [
            { reach: 0.62, amp: 0.10, freq: 2.6, speed: 1.4, a: 0.95,
              stops: [[0, '2,0,0', 0.96], [0.45, '45,3,3', 0.85], [0.80, '120,10,9', 0.45], [1, '150,16,12', 0]] },
            { reach: 0.84, amp: 0.16, freq: 1.9, speed: 2.1, a: 0.80,
              stops: [[0, '10,0,0', 0.0], [0.40, '130,10,8', 0.55], [0.78, '205,26,18', 0.30], [1, '235,44,26', 0]] },
            { reach: 1.04, amp: 0.24, freq: 1.4, speed: 2.9, a: 0.70,
              stops: [[0, '60,3,2', 0.0], [0.50, '200,22,16', 0.0], [0.82, '255,60,38', 0.35], [1, '255,110,52', 0]] },
        ];

        ctx.save();

        for (const side of [-1, 1]) {            // -1 = left edge, +1 = right edge
            const edgeX = side < 0 ? 0 : W;
            const inX = -side;                    // inward screen direction (+x for left)
            const steps = 26;

            // --- stacked wavy flame curtains (overlapping sine waves) ----------
            for (const L of LAYERS) {
                const grad = ctx.createLinearGradient(edgeX, 0, edgeX + inX * band, 0);
                for (const [p, rgb, al] of L.stops) grad.addColorStop(p, `rgba(${rgb},${al * A})`);
                ctx.fillStyle = grad;

                ctx.beginPath();
                ctx.moveTo(edgeX, -2);
                ctx.lineTo(edgeX, H + 2);         // straight outer screen edge
                for (let s = steps; s >= 0; s--) {            // wavy inner boundary, bottom -> top
                    const y = (s / steps) * H;
                    const u = y / H;
                    // big slow undulation + a faster flicker => a living, roaring edge.
                    const wob =
                        Math.sin(u * L.freq * Math.PI * 2 + t * L.speed + side * 1.3) * L.amp +
                        Math.sin(u * (L.freq * 2.7) * Math.PI * 2 - t * (L.speed * 1.7)) * (L.amp * 0.4);
                    const reach = band * (L.reach * (0.78 + 0.22 * (0.5 + 0.5 * Math.sin(t * 0.7 + side))) + wob);
                    ctx.lineTo(edgeX + inX * Math.max(0, reach), y);
                }
                ctx.closePath();
                ctx.globalAlpha = L.a;
                ctx.fill();
            }
            ctx.globalAlpha = 1;

            // --- flickering bezier tongues licking inward off the front curtain --
            const TONGUES = 7;
            ctx.shadowBlur = 18;
            for (let i = 0; i < TONGUES; i++) {
                const base = (i + 0.5) / TONGUES;
                const ry = base * H + Math.sin(t * 1.1 + i * 2.2) * H * 0.03;
                const flick = 0.5 + 0.5 * Math.sin(t * 9 + i * 1.9);
                const len = band * (0.55 + 0.65 * flick);
                const halfH = H * (0.05 + 0.03 * flick);
                const rootX = edgeX + inX * band * 0.30;
                const tipX = edgeX + inX * (band * 0.30 + len);
                const sway = Math.sin(t * 3.3 + i) * H * 0.02;

                const g = ctx.createLinearGradient(rootX, 0, tipX, 0);
                g.addColorStop(0.00, 'rgba(8, 0, 0, 0)');
                g.addColorStop(0.25, `rgba(150, 12, 10, ${0.55 * A * flick})`);
                g.addColorStop(0.70, `rgba(238, 40, 30, ${0.6 * A * flick})`);
                g.addColorStop(1.00, 'rgba(255, 110, 52, 0)');
                ctx.fillStyle = g;
                ctx.shadowColor = `rgba(220, 40, 20, ${0.7 * A})`;

                ctx.beginPath();
                ctx.moveTo(rootX, ry - halfH);
                ctx.quadraticCurveTo(rootX + inX * len * 0.5, ry - halfH * 0.3 + sway, tipX, ry + sway);
                ctx.quadraticCurveTo(rootX + inX * len * 0.5, ry + halfH * 0.3 + sway, rootX, ry + halfH);
                ctx.closePath();
                ctx.fill();
            }
            ctx.shadowBlur = 0;

            // --- rising embers (additive, so they glow where they pile up) ------
            ctx.save();
            ctx.globalCompositeOperation = 'lighter';
            const EM = 16;
            for (let i = 0; i < EM; i++) {
                const phase = (t * 0.5 + i / EM) % 1;             // 1 -> 0 rise
                const ex = edgeX + inX * band * (0.12 + 0.7 * ((i * 7) % 5) / 5) + Math.sin(t * 2 + i) * 8;
                const ey = H - phase * H * 1.05;
                ctx.globalAlpha = (1 - phase) * 0.5 * A;
                ctx.fillStyle = i % 4 === 0 ? 'rgba(255, 150, 70, 1)' : 'rgba(255, 48, 28, 1)';
                ctx.beginPath();
                ctx.arc(ex, ey, 1.2 + (1 - phase) * 2.0, 0, Math.PI * 2);
                ctx.fill();
            }
            ctx.restore();
        }

        ctx.restore();
    }

    /**
     * Boss "empowered" aura — call while the Hero's 4s Fear Status is live
     * (Player.fearAuraActive). The same roaring black-and-crimson fire wraps the
     * Boss: a bed of dark-red glow, a rising crown of flickering bezier flame
     * tongues (black roots -> bright crimson tips) curling up the silhouette,
     * swirling crimson sparks, and rising embers. Draw it BEFORE the Boss sprite
     * (like drawAura) so the figure stands inside the fire. Pass `intensity`
     * (e.g. fearAuraTimer/30) to fade it out as the debuff lapses.
     *
     * @param {number} x, y   the Boss figure centre (FX anchor), world space.
     * @param {object} [opts] { radius, time(ms), intensity }
     */
    static drawFearBossAura(ctx, x, y, opts = {}) {
        const {
            radius = 70,
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            intensity = 1,
        } = opts;
        const A = intensity;
        if (A <= 0) return;
        const t = time / 1000;
        const R = radius;

        ctx.save();
        ctx.translate(x, y);

        // 0) Bed of dark-red fire pooled around/under the figure.
        const bed = ctx.createRadialGradient(0, R * 0.5, R * 0.1, 0, R * 0.5, R * 1.25);
        bed.addColorStop(0.00, `rgba(120, 10, 8, ${0.40 * A})`);
        bed.addColorStop(0.45, `rgba(60, 4, 4, ${0.30 * A})`);
        bed.addColorStop(1.00, 'rgba(4, 0, 0, 0)');
        ctx.fillStyle = bed;
        ctx.beginPath();
        ctx.ellipse(0, R * 0.5, R * 1.25, R * 0.9, 0, 0, Math.PI * 2);
        ctx.fill();

        // 1) Rising crown of bezier flame tongues wrapping the silhouette. Roots
        //    ring the body; each rises (fire goes up) with an outward lean on the
        //    sides, sways, flickers in height, and is filled with a black-root ->
        //    crimson -> bright-red gradient (the reference heat ramp).
        const TONGUES = 16;
        for (let i = 0; i < TONGUES; i++) {
            const ang = (i / TONGUES) * Math.PI * 2;
            const rootX = Math.cos(ang) * R * 0.72;
            const rootY = Math.sin(ang) * R * 0.52 + R * 0.18;   // ring sits a touch low
            const flick = 0.5 + 0.5 * Math.sin(t * 10 + i * 1.7);
            const len = R * (0.55 + 0.6 * flick) * (0.7 + 0.3 * Math.sin(t * 1.3 + i));
            const halfW = R * (0.10 + 0.04 * flick);
            const lean = Math.sign(rootX || 1) * R * 0.18;        // lean outward on the flanks
            const sway = Math.sin(t * 3.0 + i * 1.3) * R * 0.10;
            const tipX = rootX + lean + sway;
            const tipY = rootY - len;                            // upward

            const g = ctx.createLinearGradient(rootX, rootY, tipX, tipY);
            g.addColorStop(0.00, `rgba(6, 0, 0, ${0.85 * A})`);   // near-black root
            g.addColorStop(0.30, `rgba(120, 10, 8, ${0.75 * A})`);
            g.addColorStop(0.68, `rgba(228, 32, 26, ${0.7 * A * (0.6 + 0.4 * flick)})`);
            g.addColorStop(1.00, 'rgba(255, 110, 52, 0)');        // bright fading tip
            ctx.fillStyle = g;
            ctx.shadowColor = `rgba(220, 40, 20, ${0.6 * A})`;
            ctx.shadowBlur = 14;

            // teardrop: two quadratics bowing out from the base corners to the tip.
            const px = -(tipY - rootY), py = (tipX - rootX);      // axis perpendicular
            const pl = Math.hypot(px, py) || 1;
            const nx = px / pl, ny = py / pl;
            ctx.beginPath();
            ctx.moveTo(rootX + nx * halfW, rootY + ny * halfW);
            ctx.quadraticCurveTo(rootX + (tipX - rootX) * 0.5 + nx * halfW * 1.4,
                                 rootY + (tipY - rootY) * 0.5 + ny * halfW * 1.4,
                                 tipX, tipY);
            ctx.quadraticCurveTo(rootX + (tipX - rootX) * 0.5 - nx * halfW * 1.4,
                                 rootY + (tipY - rootY) * 0.5 - ny * halfW * 1.4,
                                 rootX - nx * halfW, rootY - ny * halfW);
            ctx.closePath();
            ctx.fill();
        }
        ctx.shadowBlur = 0;

        // 2) Swirling crimson sparks + 3) rising embers (additive, last layer).
        ctx.save();
        ctx.globalCompositeOperation = 'lighter';
        const S = 20;
        for (let i = 0; i < S; i++) {
            const ang = t * (0.8 + 0.04 * i) + (i * Math.PI * 2) / S;
            const orbit = R * (0.55 + 0.35 * Math.sin(t * 1.4 + i * 1.9));
            const sx = Math.cos(ang) * orbit;
            const sy = Math.sin(ang) * orbit * 0.8 - R * 0.05;
            ctx.globalAlpha = (0.2 + 0.5 * (0.5 + 0.5 * Math.sin(t * 2.3 + i))) * A;
            ctx.fillStyle = i % 5 === 0 ? 'rgba(255, 150, 70, 1)' : 'rgba(235, 40, 24, 1)';
            ctx.beginPath();
            ctx.arc(sx, sy, 1.6 + 2.0 * ((i * 7) % 5) / 5, 0, Math.PI * 2);
            ctx.fill();
        }
        const E = 10;
        for (let i = 0; i < E; i++) {
            const phase = (t * 0.7 + i / E) % 1;
            const ex = Math.sin((i * 12.9 + t) * 1.3) * R * 0.5;
            const ey = R * 0.6 - phase * R * 1.6;
            ctx.globalAlpha = (1 - phase) * 0.55 * A;
            ctx.fillStyle = i % 3 === 0 ? 'rgba(255, 140, 60, 1)' : 'rgba(255, 50, 30, 1)';
            ctx.beginPath();
            ctx.arc(ex, ey, 1.4 + (1 - phase) * 1.7, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.restore();

        ctx.restore();
    }

    // =======================================================================
    // STEP 3 — Charged-attack VFX (procedural, Canvas-API; visual-only).
    // Style guides: the laser reference (blinding white core + red/orange bloom)
    // and darkaura.gif (roaring black/red fire). All three follow the house
    // idioms above: opts.time (ms) drives the animation, a local save()/
    // translate()/restore(), rgba gradients, shadowBlur/shadowColor glow, and
    // 'lighter' compositing for additive embers. None read or write physics.
    // =======================================================================

    /**
     * REQUIREMENT 1 — wand charge glow, drawn OVER the wand during 'groundCharge'.
     * `progress` is the 0..1 charge ratio (Player.chargeRatio): a cool blue→white
     * orb that PULSES faster and swells as it fills, then at 1.0 SNAPS to a
     * blinding red core wrapped in a strobing fiery aura + flame tongues — the
     * "ready to fire the Laser" tell. Draw it at the wand-tip world position.
     *
     * @param {CanvasRenderingContext2D} ctx
     * @param {number} x, y        wand-tip centre (world space)
     * @param {number} progress    0..1 charge ratio (>=1 == fully charged)
     * @param {object} [opts]       { time(ms), intensity, radius }
     */
    static drawWandGlow(ctx, x, y, progress = 0, opts = {}) {
        const {
            time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
            intensity = 1,
            radius = 16,
        } = opts;
        const A = intensity;
        if (A <= 0) return;
        const t = time / 1000;
        const p = Math.max(0, Math.min(1, progress));
        const ready = progress >= 0.999;
        const LITE = isLiteVfx();
        const PERF = isPerfVfx();

        // Pulse quickens as the charge builds; at full it strobes hard.
        const pulseSpeed = 2 + p * 9 + (ready ? 9 : 0);
        const pulse = 0.62 + 0.38 * Math.sin(t * pulseSpeed);
        const r = radius * (0.55 + 0.85 * p) * (0.85 + 0.30 * pulse);

        ctx.save();
        ctx.translate(x, y);
        ctx.globalCompositeOperation = 'lighter'; // glows add together

        // 1) Soft aura — cyan/white while charging, fiery red once ready.
        const aura = ctx.createRadialGradient(0, 0, r * 0.10, 0, 0, r * 1.9);
        if (ready) {
            const f = 0.6 + 0.4 * Math.sin(t * 22); // red strobe
            aura.addColorStop(0.00, `rgba(255, 244, 224, ${0.95 * A})`);
            aura.addColorStop(0.20, `rgba(255, ${Math.round(70 + 70 * f)}, 40, ${0.90 * A})`);
            aura.addColorStop(0.55, `rgba(220, 30, 24, ${0.55 * A})`);
            aura.addColorStop(1.00, 'rgba(60, 0, 0, 0)');
        } else {
            const warm = p; // 0 = cool blue, 1 = near-white
            aura.addColorStop(0.00, `rgba(255, 255, 255, ${(0.50 + 0.40 * p) * A})`);
            aura.addColorStop(0.30, `rgba(${Math.round(130 + 110 * warm)}, ${Math.round(205 - 35 * warm)}, 255, ${0.60 * A})`);
            aura.addColorStop(0.70, `rgba(70, 120, 230, ${0.30 * A})`);
            aura.addColorStop(1.00, 'rgba(20, 30, 80, 0)');
        }
        ctx.fillStyle = aura;
        ctx.beginPath();
        ctx.arc(0, 0, r * 1.9, 0, Math.PI * 2);
        ctx.fill();

        // 2) Blinding core.
        ctx.shadowBlur = PERF ? (6 + 4 * p) : (LITE ? (10 + 8 * p) : (18 + 22 * p));
        ctx.shadowColor = ready ? 'rgba(255, 60, 30, 0.95)' : 'rgba(150, 200, 255, 0.9)';
        ctx.fillStyle = `rgba(255, 255, 255, ${0.85 * A})`;
        ctx.beginPath();
        ctx.arc(0, 0, r * (ready ? 0.60 : 0.42) * pulse, 0, Math.PI * 2);
        ctx.fill();

        // 3) Orbiting sparks — more + faster as the charge climbs.
        const N = PERF ? (3 + Math.round(p * 2)) : (LITE ? (4 + Math.round(p * 4)) : (6 + Math.round(p * 10)));
        for (let i = 0; i < N; i++) {
            const ang = t * (3 + 6 * p) + (i * Math.PI * 2) / N;
            const orbit = r * (0.95 + 0.6 * Math.sin(t * 4 + i));
            const sx = Math.cos(ang) * orbit;
            const sy = Math.sin(ang) * orbit;
            ctx.globalAlpha = (0.3 + 0.5 * (0.5 + 0.5 * Math.sin(t * 6 + i))) * A;
            ctx.fillStyle = ready
                ? (i % 3 ? 'rgba(255, 70, 40, 1)' : 'rgba(255, 170, 80, 1)')
                : (i % 3 ? 'rgba(150, 210, 255, 1)' : 'rgba(230, 245, 255, 1)');
            ctx.shadowColor = ctx.fillStyle;
            ctx.shadowBlur = LITE ? 0 : 8;
            ctx.beginPath();
            ctx.arc(sx, sy, 1.3 + 2.0 * ((i * 7) % 5) / 5, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.globalAlpha = 1;

        // 4) READY: fiery flame tongues fanning up + a strobing red ring flash.
        if (ready) {
            const F = PERF ? 3 : (LITE ? 5 : 8);
            for (let i = 0; i < F; i++) {
                const ang = -Math.PI / 2 + (i / (F - 1) - 0.5) * Math.PI * 1.7 + Math.sin(t * 4 + i) * 0.15;
                const flick = 0.5 + 0.5 * Math.sin(t * 16 + i * 1.7);
                const len = r * (1.0 + 0.8 * flick);
                const tipX = Math.cos(ang) * len;
                const tipY = Math.sin(ang) * len - r * 0.2; // bias upward (fire rises)
                const hw = r * 0.22 * (0.6 + 0.4 * flick);
                const dx = tipX, dy = tipY;
                const pl = Math.hypot(dx, dy) || 1;
                const nx = -dy / pl, ny = dx / pl;
                const g = ctx.createLinearGradient(0, 0, tipX, tipY);
                g.addColorStop(0.00, 'rgba(20, 0, 0, 0)');
                g.addColorStop(0.25, `rgba(150, 12, 8, ${0.70 * A})`);
                g.addColorStop(0.70, `rgba(255, 60, 30, ${0.70 * A * flick})`);
                g.addColorStop(1.00, 'rgba(255, 150, 60, 0)');
                ctx.fillStyle = g;
                ctx.shadowColor = `rgba(255, 50, 20, ${0.7 * A})`;
                ctx.shadowBlur = PERF ? 4 : (LITE ? 8 : 14);
                ctx.beginPath();
                ctx.moveTo(nx * hw, ny * hw);
                ctx.quadraticCurveTo(dx * 0.5 + nx * hw * 1.3, dy * 0.5 + ny * hw * 1.3, tipX, tipY);
                ctx.quadraticCurveTo(dx * 0.5 - nx * hw * 1.3, dy * 0.5 - ny * hw * 1.3, -nx * hw, -ny * hw);
                ctx.closePath();
                ctx.fill();
            }
            const rf = 0.5 + 0.5 * Math.sin(t * 20);
            ctx.globalAlpha = (0.4 + 0.5 * rf) * A;
            ctx.lineWidth = 2.5;
            ctx.shadowBlur = PERF ? 4 : (LITE ? 8 : 16);
            ctx.shadowColor = 'rgba(255, 40, 20, 0.95)';
            ctx.strokeStyle = 'rgba(255, 220, 200, 0.9)';
            ctx.beginPath();
            ctx.arc(0, 0, r * (1.2 + 0.2 * rf), 0, Math.PI * 2);
            ctx.stroke();
            ctx.globalAlpha = 1;
        }

        ctx.restore();
    }

    /**
     * STAGE RE-3 — GROUND CHARGED RED ECLIPSE (the approved Stage RE-2 "INHALE
     * ECLIPSE" implosion, wired onto the Boss's grounded charged attack). This
     * REPLACES the drawWandGlow gather visual at the GROUND_LASER charge seam.
     *
     * An IMPLOSION, never an explosion: black-red eclipse energy forms OUTSIDE the
     * Boss and travels INWARD along fixed lanes, crushing into the red chest core
     * (grid 39,29 == pose chest 20,15 == where the live ground laser gathers/fires).
     * Composited from the byte-exact RE-2 key-grids:
     *   • back  (84x62) drawn behind the body region (far shard ring, floor arcs);
     *   • body  (46x48) pre-treated re-skin painted over the live groundCharge pose
     *          (near-void body + chest-core pulse), so the core reads as the focus;
     *   • front (84x62) the inward convergence that crosses the silhouette.
     * All three share the SAME centre axis as the sprite (the pose is authored at
     * grid x=19, width 46 -> centre col 42 == the 84-grid centre), so the built-in
     * matrix mirror flips the effect around exactly the Boss centre — the chest-core
     * anchor stays correct in BOTH facings and across pose frames, with no extra math.
     *
     * Tier reduction is DATA-driven (eclipseGround / *Lite / *Perf), so every tier
     * keeps the same phase timing + inward read and never falls back to a generic
     * aura. RENDER-ONLY: reads a resolved phase index + facing, touches no gameplay,
     * spawns no arrays/particles (the whole effect is these static grids).
     *
     * @param {number} centerX, feetY  the Boss sprite anchor (== drawSprite's).
     * @param {number} index           resolved phase frame 0..6 (B0..B6). Ignored
     *                                  when opts.release is set (uses R0 SNAP).
     * @param {object} opts { flip, pixelSize, release }
     */
    static drawGroundEclipse(ctx, centerX, feetY, index, opts = {}) {
        const { flip = false, pixelSize = BOSS_IDLE_PIXEL, release = false } = opts;
        const PERF = isPerfVfx(), LITE = isLiteVfx();

        // Pose footprint (46x48) authored at grid (19,14) inside the 84x62 effect
        // grid. Match drawSprite's rounding so the body re-skin lands ON the sprite.
        const BW = 46, BH = 48, BX = 19, BY = 14;
        const spriteOX = Math.round(centerX - (BW * pixelSize) / 2);
        const spriteOY = Math.round(feetY - BH * pixelSize);
        const fxOX = spriteOX - BX * pixelSize;   // effect-grid (0,0) in world px
        const fxOY = spriteOY - BY * pixelSize;

        if (release) {
            // Phase 5 — R0 SNAP outro: draw ONLY the effect cells (ash + the hot
            // cluster snapping into the muzzle point on the beam axis). The body
            // re-skin is deliberately skipped so it never fights the live fireLaser
            // pose — the real sprite shows through, the ring becomes the beam.
            const r0 = BOSS_GROUND_ECLIPSE.eclipseGroundRelease[0];
            SpriteManager.drawMatrix(ctx, r0.back, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
            SpriteManager.drawMatrix(ctx, r0.front, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
            return;
        }

        const tierKey = PERF ? 'eclipseGroundPerf' : (LITE ? 'eclipseGroundLite' : 'eclipseGround');
        const i = index < 0 ? 0 : index > 6 ? 6 : index;
        const fr = BOSS_GROUND_ECLIPSE[tierKey][i];
        const body = BOSS_GROUND_ECLIPSE.eclipseGroundBody[i];

        // back (behind the body region) -> body re-skin (over the live sprite) ->
        // front (over everything). Back cells outside the 46-wide body sit clear of
        // the sprite, so painting them here (over) reads identically to "behind".
        SpriteManager.drawMatrix(ctx, fr.back, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
        SpriteManager.drawMatrix(ctx, body, spriteOX, spriteOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
        SpriteManager.drawMatrix(ctx, fr.front, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
    }

    /**
     * STAGE RE-5 — AIR CHARGED RED ECLIPSE (the approved Stage RE-4 "IGNITION
     * ECLIPSE" detonation, wired onto the Boss's airborne charged attack). This
     * REPLACES the drawChargedAirAura + drawChargeReadyAura visuals at the AIR_DIVE
     * charge seam in Player.draw.
     *
     * A DETONATION — the exact inverse of the ground inhale: black-red energy is
     * born AT the red chest core while the Boss hovers, IGNITES, and bursts OUTWARD
     * into a starburst of long straight crystal rays around an umbral void-disc core
     * (CHEST CORE -> IGNITION -> OUTWARD EXPANSION). Composited from the byte-exact
     * RE-4 key-grids:
     *   • back  (100x88) drawn behind the body region (rays, octagon, shard scatter,
     *          the south ray aimed at the ground = the dive axis);
     *   • body  (46x48) pre-treated re-skin painted over the live airCharge pose
     *          (near-void body + chest-core envelope) — C0-C4 only;
     *   • front (100x88) the corona void-disc + halo that crosses the silhouette.
     * The pose (grid x=27, width 46 -> centre col 50 == the 100-grid centre) shares
     * the sprite's centre axis, so the built-in matrix mirror flips the whole effect
     * around exactly the Boss centre — the chest-core anchor (grid 47,29 == pose
     * chest 20,15) stays correct in BOTH facings and across pose frames, no extra math.
     *
     * The RELEASE TAIL (C5-C7) sets `release`: it draws back+front ONLY (no body
     * re-skin) so the outward-discharge decay rides over whatever live dive pose the
     * existing charged dive shows, without fighting it.
     *
     * Tier reduction is DATA-driven (eclipseAir / *Lite / *Perf), so every tier keeps
     * the same phase timing + outward read and never falls back to a generic aura.
     * RENDER-ONLY: reads a resolved phase index + facing, touches no gameplay, spawns
     * no arrays/particles (the whole effect is these static grids).
     *
     * @param {number} centerX, feetY  the Boss sprite anchor (== drawSprite's).
     * @param {number} index           resolved phase frame 0..7 (C0..C7).
     * @param {object} opts { flip, pixelSize, release }
     */
    static drawAirEclipse(ctx, centerX, feetY, index, opts = {}) {
        const { flip = false, pixelSize = BOSS_IDLE_PIXEL, release = false } = opts;
        const PERF = isPerfVfx(), LITE = isLiteVfx();

        // Pose footprint (46x48) authored at grid (27,14) inside the 100x88 effect
        // grid. Match drawSprite's rounding so the body re-skin lands ON the sprite.
        const BW = 46, BH = 48, BX = 27, BY = 14;
        const spriteOX = Math.round(centerX - (BW * pixelSize) / 2);
        const spriteOY = Math.round(feetY - BH * pixelSize);
        const fxOX = spriteOX - BX * pixelSize;   // effect-grid (0,0) in world px
        const fxOY = spriteOY - BY * pixelSize;

        const tierKey = PERF ? 'eclipseAirPerf' : (LITE ? 'eclipseAirLite' : 'eclipseAir');
        const i = index < 0 ? 0 : index > 7 ? 7 : index;
        const fr = BOSS_AIR_ECLIPSE[tierKey][i];

        // back (behind the body region) -> body re-skin (over the live sprite, C0-C4
        // only) -> front (over everything). Back cells outside the 46-wide body sit
        // clear of the sprite, so painting them here (over) reads identically to
        // "behind". On the release tail the body re-skin is skipped so the outward
        // decay never fights the live chargedDive pose.
        SpriteManager.drawMatrix(ctx, fr.back, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
        if (!release) {
            const body = BOSS_AIR_ECLIPSE.eclipseAirBody[i];
            SpriteManager.drawMatrix(ctx, body, spriteOX, spriteOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
        }
        SpriteManager.drawMatrix(ctx, fr.front, fxOX, fxOY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
    }

    /**
     * STAGE 8A-2 — the UMBRAL ORB (approved Boss combo Hit 3, the "eclipse-ball").
     * Replaces the old Dark Flame visual on the kind==='flame' projectile: a black-
     * red red-eclipse ball — an umbral void-disc `0` core in a hot `d` corona with a
     * broken `c` ring, bolt kinks and an ember tail, riding the ground forward.
     *
     * The 23x23 grid is centred on (11,11), which is the grid's own midline
     * ((23-1)/2 = 11), so drawMatrix's built-in flip mirrors the cell around exactly
     * the orb centre — the core stays anchored in BOTH travel directions with no
     * extra math. 23 cells @ pixelSize 3 = 69px ≈ the live 64px FLAME box.
     *
     * @param {number} centerX, centerY  the projectile centre (== p.x / p.y).
     * @param {number} index             O-cell 0..3 (O0 ignite / O1-O2 flight / O3 burst).
     * @param {object} opts { flip, pixelSize }
     */
    static drawComboOrb(ctx, centerX, centerY, index, opts = {}) {
        const { flip = false, pixelSize = BOSS_IDLE_PIXEL } = opts;
        const cell = BOSS_COMBO_ECLIPSE.comboOrb[index < 0 ? 0 : index > 3 ? 3 : index];
        const originX = Math.round(centerX - 11 * pixelSize);
        const originY = Math.round(centerY - 11 * pixelSize);
        SpriteManager.drawMatrix(ctx, cell, originX, originY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
    }

    /**
     * STAGE 8A-2 — the ECLIPSE BREAKER DETONATION (approved Boss combo Hit 4 finisher).
     * Replaces the old drawExplosion on the kind==='explosion' projectile: a grounded
     * black-red half-dome — void core, crystalline rays up/forward, a broken half-
     * octagon, outward shards and void-fracture skitters racing the floor line, then
     * fracture and a cooled ashfall. The floor eats everything below the floor row, so
     * it reads as a blast rooted on the ground rather than a free-floating circle.
     *
     * Anchoring (the drop-in contract's two risks, handled here):
     *   • FLOOR-PINNED — the grid's floor row (48) is placed on `floorY` (the arena
     *     floor line), NOT the grid's own bottom, so the half-dome sits on the ground.
     *   • CX=38 MIRROR — the blast's impact core is at grid column 38, which is NOT the
     *     72-grid midline (35.5). A naive drawMatrix flip mirrors around the midline
     *     and would shift the core in left-facing, so we reflect the anchor column
     *     around CX itself: display-col(38) is 38 un-flipped, (71-38)=33 flipped — pin
     *     THAT column to centerX. The impact origin then stays on the Boss/projectile
     *     in both facings.
     * Scale is caller-driven via `pixelSize` (the finisher passes EXPL.drawPixel so the
     * DRAWN burst reads a touch taller than the Boss body; the AABB hitbox is separate).
     * Both anchors above scale from centerX / floorY, so the pin + core-mirror hold at
     * any pixelSize.
     *
     * @param {number} centerX  the blast impact x (== the projectile p.x).
     * @param {number} floorY   the arena floor line (the Boss feet line).
     * @param {number} index    D-cell 0..3 (D0 flash / D1 burst / D2 fracture / D3 ash).
     * @param {object} opts { flip, pixelSize }
     */
    static drawComboDetonation(ctx, centerX, floorY, index, opts = {}) {
        const { flip = false, pixelSize = BOSS_IDLE_PIXEL } = opts;
        const CX = 38, FLOOR_ROW = 48, W = 72;
        const cell = BOSS_COMBO_ECLIPSE.comboDetonation[index < 0 ? 0 : index > 3 ? 3 : index];
        const anchorCol = flip ? (W - 1 - CX) : CX;   // reflect CX for the flipped draw
        const originX = Math.round(centerX - anchorCol * pixelSize);
        const originY = Math.round(floorY - FLOOR_ROW * pixelSize);
        SpriteManager.drawMatrix(ctx, cell, originX, originY, pixelSize, { flip, palette: BOSS_REDESIGN_PALETTE });
    }

    /**
     * REQUIREMENT 2 — the fully-charged ground LASER BEAM. A massive, screen-
     * spanning bolt fired from (x, y) along `facing`: a blinding white-hot core
     * sheathed in searing orange and deep-red glow strokes under heavy
     * shadowBlur (the reference look), capped by a radial muzzle flare with
     * flickering lens-flare star rays at the source. Draw it in world space
     * (e.g. for the 'laser' projectile), OVER the Boss.
     *
     * @param {CanvasRenderingContext2D} ctx
     * @param {number} x, y      beam origin (the wand muzzle), world space
     * @param {number} facing    +1 / -1 (the beam shoots this way; mirrors it)
     * @param {object} [opts]      { time(ms), intensity, length, thickness,
     *                               progress } progress(0..1) drives an ignition
     *                               ramp-in + fade-out; omit for a steady beam.
     */
    static drawLaserBeam(ctx, x, y, facing = 1, opts = {}) {
        const { time = (typeof performance !== 'undefined' ? performance.now() : Date.now()),
                intensity = 1, length = 2400, thickness = 46, progress = null } = opts;
        let env = 1;
        if (progress != null) {
            const pr = Math.max(0, Math.min(1, progress));
            const inP = Math.min(1, pr / 0.12);
            const outP = pr > 0.75 ? Math.max(0, 1 - (pr - 0.75) / 0.25) : 1;
            env = Math.min(inP, outP);
        }
        const A = intensity * env;
        if (A <= 0) return;
        const PERF = isPerfVfx();
        const E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a', UMB = '#14101c';
        const frame = Math.floor(time / 60);
        const PX = Math.max(2, Math.round(thickness / 12));
        const L = length;
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.scale(facing, 1);
        ctx.shadowBlur = 0;
        const baseGA = ctx.globalAlpha * A;
        // sampler R0C3: symmetric horizontal bands E2 rim / E1 / UMB void core / E1 / E2 rim
        if (!PERF) { ctx.globalAlpha = baseGA * 0.13; ctx.fillStyle = E2; ctx.fillRect(0, -4.5 * PX, L, 9 * PX); }
        ctx.globalAlpha = baseGA;
        const band = (gy, gh, col) => { ctx.fillStyle = col; ctx.fillRect(0, gy * PX, L, gh * PX); };
        band(-4, 1, E2); band(-3, 2, E1); band(-1, 3, UMB); band(2, 2, E1); band(4, 1, E2);
        // hot E3 filament dashes crawling along top & bottom sheath rows
        ctx.fillStyle = E3;
        const dashN = Math.floor(L / (PX * 8));
        for (let i = 0; i < dashN; i++) {
            if ((i + frame) % 2) continue;
            const bx = (i * 8) * PX + ((frame * 2) % 8) * PX;
            ctx.fillRect(bx, -3 * PX, 3 * PX, PX);
            ctx.fillRect(bx + 4 * PX, 3 * PX, 3 * PX, PX);
        }
        // muzzle flare (E2 flare, E3 hot, UMB core) at the source
        ctx.fillStyle = E2; ctx.fillRect(-2 * PX, -4 * PX, 4 * PX, 9 * PX);
        ctx.fillStyle = E3; ctx.fillRect(-1 * PX, -3 * PX, 3 * PX, 6 * PX);
        ctx.fillStyle = UMB; ctx.fillRect(0, -1 * PX, 2 * PX, 3 * PX);
        ctx.fillStyle = E1; ctx.fillRect(-3 * PX, -5 * PX, 2 * PX, 2 * PX); ctx.fillRect(-3 * PX, 4 * PX, 2 * PX, 2 * PX);
        ctx.restore();
    }

    /**
     * REQUIREMENT 3 — the charged-attack aura: roaring, chaotic BLACK & RED fire
     * wrapping the Boss while 'airCharge' is held and through the 'chargedDive'
     * (style: darkaura.gif). A black/crimson core haze, a turbulent double crown
     * of bezier flame tongues (black roots → blood-red → bright tips), drifting
     * black smoke puffs, plus chaotic additive embers and white-hot crackle
     * sparks. Draw it BEFORE the Boss sprite (like drawAura) so it stands inside
     * the fire. Pass `intensity` to fade it in/out.
     *
     * @param {CanvasRenderingContext2D} ctx
     * @param {number} x, y      the Boss figure centre (FX anchor), world space
     * @param {object} [opts]     { radius, time(ms), intensity }
     */
    static drawChargedAirAura(ctx, x, y, opts = {}) {
        const { radius = 80, time = (typeof performance !== 'undefined' ? performance.now() : Date.now()), intensity = 1 } = opts;
        const A = intensity;
        if (A <= 0) return;
        const PERF = isPerfVfx();
        const E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a', UMB = '#14101c';
        const PX = Math.max(2, Math.round(radius / 16));
        const frame = Math.floor(time / 90);
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.shadowBlur = 0;
        const baseGA = ctx.globalAlpha * Math.min(1.2, A);
        ctx.globalAlpha = baseGA;
        // Central charge motif = a fan of SPACED, flickering vertical ember shards
        // (1-block wide, transparent gaps between them) — a shaped, animated pixel
        // motif, NOT a flat black rectangle. Heights breathe per frame so it lives.
        const shardX = [-5, -3, -1, 1, 3, 5];
        for (let s = 0; s < shardX.length; s++) {
            const sx = shardX[s];
            const h = 3 + ((frame + s * 2 + Math.abs(sx)) % 5);           // 3..7 tall, staggered
            ctx.fillStyle = Math.abs(sx) >= 3 ? E0 : UMB;                 // outer ember-dark, inner void
            ctx.fillRect(sx * PX, -h * PX, PX, h * 2 * PX);
            ctx.fillStyle = (s % 2) ? E2 : E1;                           // hot ember tips
            ctx.fillRect(sx * PX, -h * PX, PX, PX);
            ctx.fillRect(sx * PX, (h - 1) * PX, PX, PX);
        }
        // small pulsing hot core between the inner shards
        ctx.fillStyle = E3; ctx.fillRect(-PX, (frame % 2) ? -PX : 0, PX, PX); ctx.fillRect(0, (frame % 2) ? 0 : -PX, PX, PX);
        const pts = [[0, -9, 0, 1], [8, -6, -1, 1], [10, 0, -1, 0], [8, 7, -1, -1], [0, 9, 0, -1], [-8, 7, 1, -1], [-10, 0, 1, 0], [-8, -6, 1, 1]];
        const g = frame % 3;
        for (const [px, py, dx, dy] of pts) {
            const gx = px + dx * g, gy = py + dy * g;
            ctx.fillStyle = E2; ctx.fillRect(gx * PX, gy * PX, PX, PX);
            ctx.fillStyle = E1; ctx.fillRect((gx + dx) * PX, (gy + dy) * PX, PX, PX);
            if (!PERF) { ctx.globalAlpha = baseGA * 0.8; ctx.fillStyle = E0; ctx.fillRect((gx + dx * 2) * PX, (gy + dy * 2) * PX, PX, PX); ctx.globalAlpha = baseGA; }
        }
        ctx.globalAlpha = baseGA * 0.4; ctx.fillStyle = E1; ctx.fillRect(-10 * PX, 12 * PX, 20 * PX, 2 * PX);
        ctx.globalAlpha = baseGA * 0.5; ctx.fillStyle = E0; ctx.fillRect(-12 * PX, 14 * PX, 24 * PX, PX);
        ctx.restore();
    }

    /**
     * STEP 2 — the "CHARGE READY" aura. Rendered CONTINUOUSLY while
     * Player.isChargeReady is true (Boss airborne, attack button still held, the
     * 1-second charge complete). A violent, pulsing dark-red & black energy
     * burst CONTAINED around the Boss — the "this is about to detonate" tell.
     *
     * Style guides — darkredaura1/2:
     *   • a blinding white / bright-red CORE pinned on the figure,
     *   • a roaring crimson energy RING that breathes with the pulse,
     *   • black-rooted crimson FLARES stabbing outward into the dark,
     *   • everything backed by deep black for maximum contrast.
     *
     * House idioms (same as drawAura / drawChargedAirAura): `time` (ms) drives the
     * loop, a local save()/translate()/restore(), rgba gradient heat ramps
     * (near-black root → crimson → bright tip), HIGH shadowBlur with red/crimson
     * shadowColor for the menacing glow, and 'lighter' compositing for the
     * additive cores/embers. Visual-only — it never reads or writes physics/AI.
     *
     * Signature is (ctx, x, y, time) as requested; an optional trailing `opts`
     * ({ radius, intensity }) is accepted so callers can scale / fade it exactly
     * like the sibling auras. Draw it BEFORE the Boss sprite (like drawAura) so
     * the figure stands inside the energy; the bright additive core is layered so
     * it still reads over the silhouette.
     *
     * @param {CanvasRenderingContext2D} ctx
     * @param {number} x, y   the Boss figure centre (FX anchor), world space
     * @param {number} time   animation clock in ms (e.g. performance.now())
     * @param {object} [opts] { radius, intensity }
     */
    static drawChargeReadyAura(ctx, x, y, time = (typeof performance !== 'undefined' ? performance.now() : Date.now()), opts = {}) {
        const { radius = 90, intensity = 1 } = opts;
        const A = intensity;
        if (A <= 0) return;
        const E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a', UMB = '#14101c';
        const t = time / 1000, beat = 0.5 + 0.5 * Math.sin(t * 8);
        const PX = Math.max(2, Math.round(radius / 15)) + (beat > 0.6 ? 1 : 0);   // pulse the block size
        const frame = Math.floor(time / 70);
        ctx.save();
        ctx.translate(Math.round(x), Math.round(y));
        ctx.shadowBlur = 0;
        const baseGA = ctx.globalAlpha * Math.min(1.3, A);
        ctx.globalAlpha = baseGA;
        // Ready state: same SPACED ember heat-shard fan, taller + more violent, with
        // a flashing hot core between the inner shards (no flat rectangle).
        const shardX = [-5, -3, -1, 1, 3, 5];
        for (let s = 0; s < shardX.length; s++) {
            const sx = shardX[s];
            const h = 5 + ((frame + s * 2 + Math.abs(sx)) % 6);          // taller than the hold
            ctx.fillStyle = Math.abs(sx) >= 3 ? E0 : UMB;
            ctx.fillRect(sx * PX, -h * PX, PX, h * 2 * PX);
            ctx.fillStyle = (s % 2) ? E3 : E2;                          // hotter tips (ready)
            ctx.fillRect(sx * PX, -h * PX, PX, PX);
            ctx.fillRect(sx * PX, (h - 1) * PX, PX, PX);
        }
        ctx.fillStyle = beat > 0.5 ? E3 : E2; ctx.fillRect(-PX, -PX, 2 * PX, 2 * PX);   // flashing hot core
        const inner = [[0, -4], [4, -3], [5, 0], [4, 3], [0, 4], [-4, 3], [-5, 0], [-4, -3]];
        for (const [px, py] of inner) { ctx.fillStyle = E3; ctx.fillRect(px * PX, py * PX, PX, PX); }
        const outer = [[0, -9, 0, 1], [8, -6, -1, 1], [10, 0, -1, 0], [8, 7, -1, -1], [0, 9, 0, -1], [-8, 7, 1, -1], [-10, 0, 1, 0], [-8, -6, 1, 1]];
        const g = frame % 3;
        for (const [px, py, dx, dy] of outer) {
            const gx = px + dx * g, gy = py + dy * g;
            ctx.fillStyle = E2; ctx.fillRect(gx * PX, gy * PX, PX, PX);
            ctx.fillStyle = E1; ctx.fillRect((gx + dx) * PX, (gy + dy) * PX, PX, PX);
        }
        ctx.globalAlpha = baseGA * 0.45; ctx.fillStyle = E1; ctx.fillRect(-12 * PX, 12 * PX, 24 * PX, 2 * PX);
        ctx.restore();
    }

    // =======================================================================
    //  STAGE 7A-1 — BOSS AFK INTIMIDATION VFX (tools/redesign/afk_spec.md §4-§7)
    //  Every cell below is a verbatim port of the approved afk_gen.js paint()
    //  calls that produced afk_v1.png. Hard fillRect blocks only: no shadowBlur,
    //  no gradients, no curves, no soft particles, no big solid rectangles.
    //  Ramp: VOID #060409 · UMB #14101c · SMK #1a1420 · E0 #6e0f1c · E1 #a8182a
    //        · E2 #e0263a · E3 #ff5a4a.  Hero-owned steel/icy tones for the
    //  wall-bounce + hesitation arc (the repulsion is NOT a damaging attack).
    // =======================================================================

    /**
     * The chest-point pressure snap that fires the barrier (afk_gen barrier cell 1).
     * Hot core, umbral diamond, radial ticks pointing OUTWARD (a push, not a gather),
     * plus the first hint of the wave walls detaching. Anchor on the Boss chest core.
     */
    static drawIntimidationFlare(ctx, x, y, opts = {}) {
        const { size = 144, progress = 0 } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1) return;
        const PERF = isPerfVfx();
        const PX = Math.max(2, Math.round(size / 36));
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        ctx.translate(Math.round(x), Math.round(y));
        ctx.globalAlpha = baseGA * (1 - p * p);
        const R = (gx, gy, gw, gh, color) => { ctx.fillStyle = color; ctx.fillRect(gx * PX, gy * PX, gw * PX, gh * PX); };
        R(-1, -1, 2, 2, '#ff5a4a');                                            // hot core
        [[-4, 0], [4, 0], [0, -4], [0, 4], [-3, -2], [3, -2], [-3, 2], [3, 2]]
            .forEach(([dx, dy]) => R(dx, dy, 1, 1, '#060409'));                // umbral diamond
        [[-8, 0, 3, 1], [6, 0, 3, 1], [0, -8, 1, 3], [0, 6, 1, 3]]
            .forEach(([dx, dy, w, h]) => R(dx, dy, w, h, '#a8182a'));          // outward ticks
        if (!PERF) {
            [[-7, -6, 2, 1], [6, -6, 2, 1], [-7, 6, 2, 1], [6, 6, 2, 1]]
                .forEach(([dx, dy, w, h]) => R(dx, dy, w, h, '#6e0f1c'));
            [[-6, -3], [6, -3], [-6, 3], [6, 3]].forEach(([dx, dy]) => R(dx, dy, 1, 1, '#1a1420'));
            [[-11, -3, 1, 2], [-11, 2, 1, 2], [10, -3, 1, 2], [10, 2, 1, 2]]   // walls detaching
                .forEach(([dx, dy, w, h]) => R(dx, dy, w, h, '#6e0f1c'));
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    /**
     * The travelling black/dark-red pressure WALL (afk_gen `paintWave` ph 1/2/3).
     * A vertical dithered void body with an ember leading edge, crest sparks,
     * pressure teeth, smoke wake and a floor skim — never a rectangle, never smoke.
     * `progress` (0..1 of the wave's life) steps near-wall -> wide/dim -> dissolve.
     * Anchored so the wave's foot sits on `groundY`; `dir` is its travel direction.
     */
    static drawPressureWave(ctx, x, groundY, dir = 1, opts = {}) {
        const { progress = 0, height = 160 } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1) return;
        const LITE = isLiteVfx(), PERF = isPerfVfx();
        const HG = 40;                                     // sheet rows of the wave
        const PX = Math.max(2, Math.round(height / HG));
        const d = dir >= 0 ? 1 : -1;
        const UMB = '#14101c', SMK = '#1a1420', E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a';
        const baseGA = ctx.globalAlpha;
        const ox = Math.round(x), oy = Math.round(groundY - HG * PX);
        ctx.save();
        ctx.shadowBlur = 0;
        // Cell painter: gx grows along travel, so a left-going wave is a true mirror.
        const R = (gx, gy, gw, gh, color, a = 1) => {
            const sx = d > 0 ? gx : -(gx + gw);
            ctx.globalAlpha = baseGA * a;
            ctx.fillStyle = color;
            ctx.fillRect(ox + sx * PX, oy + gy * PX, gw * PX, gh * PX);
        };

        if (p > 0.82) {
            // DISSOLVE — vertical shard remnants + scattered motes (afk_gen ph 3).
            const f = 1 - (p - 0.82) / 0.18;
            [[0, 7, 5], [3, 20, 6], [-2, 30, 4], [2, 37, 2]].forEach(([gx, gy, ln], i) =>
                R(gx, gy, 1, ln, i % 2 ? SMK : E0, f));
            if (!PERF) [[-4, 12], [5, 25], [-3, 34], [6, 10]].forEach(([gx, gy]) => R(gx, gy, 1, 1, E0, f * 0.9));
            ctx.globalAlpha = baseGA;
            ctx.restore();
            return;
        }

        const wide = p > 0.55;                             // ph2: broader + dimmer
        const bulge = wide ? 4 : 6;
        const bodyCols = PERF ? 2 : (wide ? 2 : 3);
        const alpha = wide ? 0.82 : 1;
        for (let i = 0; i <= HG; i++) {
            const s = Math.sin((i / HG) * Math.PI);
            const xo = Math.round(bulge * s);
            R(xo, i, 1, 1, wide ? E1 : E2, alpha);                              // leading edge
            for (let b = 1; b <= bodyCols; b++) {
                if ((xo - b + i) % 3 !== 0) R(xo - b, i, 1, 1, UMB, alpha);     // dithered void body
            }
            if (!PERF && i % (LITE ? 8 : 4) === 0) R(xo - (wide ? 5 : 6), i, 2, 1, SMK, alpha * 0.85);
        }
        if (!PERF) {
            [0.25, 0.5, 0.75].forEach((t) => {                                  // crest sparks
                const gy = Math.round(HG * t), xo = Math.round(bulge * Math.sin(t * Math.PI));
                R(xo + 1, gy, 1, 1, E3, alpha);
            });
            [0.18, 0.38, 0.62, 0.82].forEach((t) => {                           // pressure teeth
                const gy = Math.round(HG * t), xo = Math.round(bulge * Math.sin(t * Math.PI));
                R(xo + 1, gy - 1, wide ? 1 : 2, 1, E1, alpha);
                if (!wide && !LITE) R(xo + 3, gy - 1, 1, 1, E0, alpha);
            });
        }
        R(-8, HG, 12, 1, UMB, alpha);                                           // floor skim
        R(2, HG, 3, 1, E0, alpha); R(6, HG - 1, 2, 1, E1, alpha);
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    /**
     * The sword-plant floor contact (afk_gen crack cells 1-2): an E3 impact wink,
     * then jagged cracks with an ember seep and two slow motes. World-anchored at
     * the plant column; `age` is 0..1 over its whole life, `fade` scales it out.
     */
    static drawPlantCrack(ctx, x, groundY, opts = {}) {
        const { age = 0, fade = 1, px = 3 } = opts;
        if (fade <= 0) return;
        const PERF = isPerfVfx();
        const E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a', CRK = '#0c0a12', GDK = '#3a1014';
        const baseGA = ctx.globalAlpha;
        const ox = Math.round(x), oy = Math.round(groundY);
        ctx.save();
        ctx.shadowBlur = 0;
        const R = (gx, gy, gw, gh, color, a = 1) => {
            ctx.globalAlpha = baseGA * a * fade;
            ctx.fillStyle = color;
            ctx.fillRect(ox + gx * px, oy + gy * px, gw * px, gh * px);
        };
        if (age < 0.12) {
            // IMPACT WINK — hot cross + diagonal sparks + the first crack dashes.
            const f = 1 - age / 0.12;
            R(0, -4, 1, 3, E3, f); R(-1, -3, 3, 1, E3, f);
            [[-3, -4], [3, -4], [-2, -2], [2, -2]].forEach(([gx, gy]) => R(gx, gy, 1, 1, E2, f));
            R(-5, 0, 2, 1, CRK, f); R(4, 0, 2, 1, CRK, f);
        } else {
            // SETTLED — jagged cracks, ember seep inside, two slow rising motes.
            R(-2, 0, 2, 1, CRK); R(-4, 1, 2, 1, CRK); R(-7, 2, 3, 1, CRK);
            R(1, 0, 2, 1, CRK); R(3, 1, 3, 1, CRK); R(6, 2, 2, 1, CRK);
            R(-3, 1, 1, 1, GDK); R(4, 0, 1, 1, GDK);
            R(-2, 1, 1, 1, E0); R(2, 1, 1, 1, E0); R(-5, 2, 1, 1, E0); R(5, 2, 1, 1, E0);
            R(-1, 0, 1, 1, E1); R(1, 1, 1, 1, E0);
            if (!PERF) {
                const rise = Math.floor(age * 26) % 9;
                R(-4, -3 - rise, 1, 1, E0, 0.85); R(5, -5 - ((rise + 4) % 9), 1, 1, E1, 0.7);
            }
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    /**
     * The intimidation aura (afk_gen `paintAura`, aura cells 1-3). The ONLY boss
     * aura whose motion signature is outward + DOWNWARD: a spreading floor-shadow
     * pool from the plant point, hanging void shards that SINK (never orbit, never
     * rise), two motionless pressure marks, a chest-core heartbeat ring, and three
     * slow rising motes. Zero violet, no flame, no convergence — so it can never be
     * confused with drawAura / drawFearBossAura / the charge auras.
     *
     * Anchored on the Boss SPRITE MATRIX origin so every cell lands exactly where
     * afk_gen placed it (plant col +31, floor row +47, chest core +19,+15).
     * Draw BEFORE the sprite (drawAura idiom).
     *
     * @param {number} originX,originY top-left of the drawn 46x48 boss frame.
     * @param {number} px             the frame's pixelSize.
     * @param {object} opts { shardPhase 0..2, beat 0..2, intensity, flip }
     */
    static drawIntimidationAura(ctx, originX, originY, px, opts = {}) {
        const { shardPhase = 0, beat = 0, intensity = 1, flip = false } = opts;
        if (intensity <= 0) return;
        const LITE = isLiteVfx(), PERF = isPerfVfx();
        const VOID = '#060409', UMB = '#14101c', E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a';
        const ph = ((shardPhase % 3) + 3) % 3;
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        // Cell coords are columns/rows of the 46x48 matrix (may run outside it).
        const R = (cx, cy, cw, ch, color, a = 1) => {
            const fx = flip ? (45 - (cx + cw - 1)) : cx;
            ctx.globalAlpha = baseGA * a * intensity;
            ctx.fillStyle = color;
            ctx.fillRect(originX + fx * px, originY + cy * px, cw * px, ch * px);
        };
        const plantX = 31, floorY = 47, coreX = 19, coreY = 15;

        // (1) spreading floor-shadow pool from the plant point, broken ember rim.
        const spread = 15 + ph * 3;
        for (let dx = -spread; dx <= spread; dx++) {
            if ((dx + ph) % 3 === 0) continue;
            R(plantX + dx, floorY + 1, 1, 1, UMB, 0.85);
            if (Math.abs(dx) > spread - 6 && dx % 2 === 0) R(plantX + dx, floorY + 2, 1, 1, UMB, 0.5);
        }
        R(plantX - spread, floorY, 2, 1, E0);
        R(plantX + spread - 1, floorY, 2, 1, E0);
        if (!PERF) [[-8, 2], [7, 2], [-13, 1], [12, 1]].forEach(([dx, dy]) => R(plantX + dx, floorY + dy, 1, 1, E0, 0.8));

        // (2) hanging void shards — they SINK 1px per phase (per-shard offset).
        const shards = [
            [-6, 12, 4, 1], [0, 4, 5, 2], [10, -3, 4, 1], [22, -5, 6, 2],
            [33, -2, 4, 1], [42, 5, 5, 2], [48, 14, 3, 1],
        ];
        const shardCount = PERF ? 4 : shards.length;
        for (let i = 0; i < shardCount; i++) {
            const [sx, sy, ln, wd] = shards[i];
            const sink = (ph + i) % 3;
            R(sx, sy + sink, wd, ln, VOID);
            R(sx, sy + sink, wd, 1, (i % 3 === 0 && sink === 0) ? E1 : E0);   // cap (occasional wink)
            if (!LITE && i % 3 === 1) R(sx, sy + sink + ln, 1, 1, E0, 0.7);   // sparse drip tips
        }

        // (3) two static pressure marks hugging the body (unnatural stillness).
        if (!PERF) {
            R(6, 20, 1, 6, VOID); R(6, 26, 1, 1, E0, 0.8);
            R(40, 18, 1, 6, VOID); R(40, 24, 1, 1, E0, 0.8);
        }

        // (4) chest-core heartbeat: rest -> tight E1 ring -> wide fading E0 ring.
        if (beat === 1) {
            [[-5, 0, 1, 2], [5, 0, 1, 2], [0, -4, 2, 1], [0, 4, 2, 1],
             [-4, -3, 1, 1], [4, 3, 1, 1], [4, -3, 1, 1], [-4, 3, 1, 1]]
                .forEach(([dx, dy, w, h]) => R(coreX + dx, coreY + dy, w, h, E1));
        } else if (beat === 2) {
            [[-9, 0, 1, 2], [9, 0, 1, 2], [0, -7, 2, 1], [0, 7, 2, 1],
             [-7, -5, 1, 1], [7, 5, 1, 1], [-7, 5, 1, 1], [7, -5, 1, 1]]
                .forEach(([dx, dy, w, h]) => R(coreX + dx, coreY + dy, w, h, E0, 0.85));
        }

        // (5) three slow rising ember motes — the only upward motion in the state.
        if (!PERF) {
            const motes = [[-3, 30, E1], [45, 26, E0], [26, -8, E2]];
            const moteCount = LITE ? 2 : 3;
            for (let i = 0; i < moteCount; i++) {
                const [mx, my, k] = motes[i];
                R(mx, my - ph * 2 - i, 1, 1, k);
            }
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    // =======================================================================
    // STAGE 7A-2C — "CURSE-PRESSURE" SCREEN DARKENING (afk2_spec.md §A)
    // -----------------------------------------------------------------------
    // Replaces the rejected quantized RECTANGULAR corner bands. Five organic
    // systems, ported cell-for-cell from `tools/redesign/afk2_gen.js paintCurse`
    // (the generator that rendered the approved afk2_v1.png):
    //
    //   0  pressure haze   quantized dither field keyed on a NOISY edge-distance
    //                      (75/50/25% density bands) — the noise kills every
    //                      straight seam a plain inset band would leave.
    //   1  curse-tongues   irregular tent profiles rising off the bottom edge,
    //                      2 layers + sparse 1px flame spikes, dither-broken tops.
    //   2  void-folds      the same builder hanging off the top edge, wider and
    //                      rounder, with 1px drip tails off the apexes.
    //   3  side tongues    lateral profiles biased hard toward the corners, so the
    //                      CORNERS darken where systems 1+2+3 overlap. That overlap
    //                      IS the replacement for the old corner rectangles.
    //   4  void petals     detached angular shards drifting inside the dark zone.
    //
    // Only accents: E0 caps on tongue apexes, one E1 wink per beat, petal glints.
    // No straight band edge anywhere; every boundary is a tongue silhouette, a
    // dither, or a petal. Hard fillRect blocks on a quantized cell grid — no
    // gradients, no shadowBlur, no smooth alpha wash.
    //
    // The whole screen-space layer is deterministic per (size, tier, phase), so
    // each of the 3 breathing phases is BAKED ONCE into an offscreen canvas and
    // then blitted 1:1 per frame (`intensity` rides on globalAlpha). Where no
    // canvas can be created (headless), it falls back to painting the same cells
    // directly. Either way the pixels are identical.
    // =======================================================================

    /** Deterministic hash noise (afk2_gen.js `rnd`). */
    static _curseRnd(i, s) {
        const v = Math.sin(i * 127.1 + s * 311.7) * 43758.5453;
        return v - Math.floor(v);
    }

    /**
     * One irregular tent profile along an edge (afk2_gen.js `prof`).
     * `curve` < 1 = round fold, > 1 = sharp flame. `biasFn` presses the profile
     * down toward the screen centre — the readability contract. `grow` = phase.
     */
    static _curseProf(w, seed, minH, maxH, minSpan, maxSpan, curve, biasFn, grow) {
        const rnd = SpriteManager._curseRnd;
        const hs = new Array(w).fill(0);
        let x = 0, i = 0;
        while (x < w) {
            const span = minSpan + Math.floor(rnd(i, seed) * (maxSpan - minSpan + 1));
            let peak = minH + Math.floor(rnd(i, seed + 7) * (maxH - minH + 1));
            if ((i + grow) % 3 === 0) peak += 1;                        // breathing growth
            const apex = x + Math.floor(span / 2);
            for (let k = 0; k <= span && x + k < w; k++) {
                const d = Math.min(1, Math.abs(x + k - apex) / Math.max(1, span / 2));
                const hh = Math.round(peak * Math.pow(1 - d, curve));
                if (hh > hs[x + k]) hs[x + k] = hh;
            }
            x += span; i++;
        }
        if (biasFn) for (let j = 0; j < w; j++) hs[j] = Math.round(hs[j] * biasFn(j / Math.max(1, w - 1)));
        return hs;
    }

    /**
     * Per-tier knobs, in GRID CELLS, derived from the grid height so the look is
     * identical at any viewport (afk2_spec §C). tier 0 normal / 1 lite / 2 perf.
     * Every tier keeps organic tongues + corner pressure — no tier ever falls
     * back to a rectangle.
     */
    static _curseKnobs(GH, tier) {
        // Depth ratios are afk2_gen.js `knobsFor(h, 3)` — the approved V3 "unified"
        // variant, whose screen mock is 104x58 (16:9, same as a real viewport).
        const f = (r) => Math.max(2, Math.round(GH * r));
        // Tongue SPANS scale with their own height rather than being fixed in cells.
        // The ratios below reproduce the mock's absolute spans exactly at its scale
        // (bMax 12 -> [8,13], tMax 9 -> [9,14], sideMax 8 -> [7,12]) and hold the
        // same tongue COUNT and aspect at any viewport — a fixed cell span would
        // stretch them into needles on a taller screen.
        const span = (max, lo, hi) => [Math.max(3, Math.round(max * lo)), Math.max(5, Math.round(max * hi))];
        const bMax = f(0.21), tMax = f(0.16), sideMax = f(0.14);
        const k = {
            // Haze depth is the ONE knob pulled below the mock's (0.27): the mock's
            // screen is a short letterbox, so 27% of its height stops at the floor,
            // while on a real 16:9 viewport it climbs over the fighters. 0.18 keeps
            // the haze under the floor line — the §A centre-readability contract.
            haze: f(0.18), hazeBands: 3,
            bMax, bMin: f(0.08), bSpan: span(bMax, 0.667, 1.083), bCurve: 1.1, backA: 0.62,
            tMax, tMin: f(0.06), tSpan: span(tMax, 1.0, 1.556), tCurve: 0.8,
            sideMax, sideSpan: span(sideMax, 0.875, 1.5), sideA: 0.58,
            petals: 6, drips: 2, spikes: 3, mid: true,
        };
        if (tier >= 1) {                       // lite: fewer motifs, 2 haze bands
            k.hazeBands = 2; k.spikes = 0; k.drips = 0; k.petals = 3;
        }
        if (tier >= 2) {                       // performance: back tongue layer only
            k.hazeBands = 1; k.mid = false; k.petals = 2;
            k.backA = 0.72; k.sideA = 0.66;    // one layer, so it carries the weight
        }
        return k;                              // geometry is identical in every tier
    }

    /**
     * Emit the whole darkening as CELL rects through `P(x, y, w, h, color, alpha)`.
     * Vertical/horizontal runs are pre-merged, so a tongue column is one rect.
     */
    static _cursePaintCells(P, GW, GH, k, phase, seed) {
        const rnd = SpriteManager._curseRnd;
        const prof = SpriteManager._curseProf;
        const VOID = '#060409', DEEP = '#0a0410', E0 = '#6e0f1c', E1 = '#a8182a';
        const edgeBias = (t) => Math.min(1, 0.55 + 0.45 * (Math.abs(t - 0.5) * 2 + 0.15));
        const sideBias = (t) => 0.2 + 0.8 * Math.pow(Math.abs(t - 0.5) * 2, 1.3);
        const PETALS = [
            [[0, 0], [1, 0], [2, 0], [0, 1], [1, 1], [2, 1], [1, 2]],
            [[0, 0], [1, 0], [1, 1], [2, 1], [2, 2]],
            [[0, 0], [0, 1], [1, 1]],
            [[0, 0], [1, 0], [0, 1], [1, 1], [2, 0]],
        ];

        // --- (0) quantized dither pressure-haze, under everything ---------------
        if (k.haze > 0) {
            const d0 = k.haze * 0.35, d1 = k.haze * 0.7, reach = k.haze + 4;
            for (let y = 0; y < GH; y++) {
                const rowInner = Math.min(y, GH - 1 - y) > reach;
                let run = -1;
                for (let x = 0; x < GW; x++) {
                    if (rowInner && x >= reach && x < GW - reach) {   // clean interior: skip
                        if (run >= 0) { P(run, y, x - run, 1, VOID, 0.45); run = -1; }
                        x = GW - reach - 1;
                        continue;
                    }
                    const d = Math.min(x, GW - 1 - x, y, GH - 1 - y)
                            + rnd(x * 7 + y * 13, seed + 51) * 6 - 3;   // ±3px noise: no seams
                    let on = false;
                    if (d < d0) on = (x + y + phase) % 4 !== 0;                       // 75%
                    else if (k.hazeBands >= 2 && d < d1) on = (x + y + phase) % 2 === 0;  // 50%
                    else if (k.hazeBands >= 3 && d < k.haze) on = x % 2 === 0 && (y + phase) % 2 === 0; // 25%
                    if (on) { if (run < 0) run = x; }
                    else if (run >= 0) { P(run, y, x - run, 1, VOID, 0.45); run = -1; }
                }
                if (run >= 0) P(run, y, GW - run, 1, VOID, 0.45);
            }
        }

        // --- (1) rising curse-tongues (bottom) ---------------------------------
        const back = prof(GW, seed, k.bMin, k.bMax, k.bSpan[0], k.bSpan[1], k.bCurve, edgeBias, phase);
        const mid = k.mid
            ? prof(GW, seed + 13, Math.max(2, Math.round(k.bMin * 0.7)), Math.max(3, Math.round(k.bMax * 0.65)),
                Math.max(3, Math.round(k.bSpan[0] * 0.63)), Math.max(4, Math.round(k.bSpan[1] * 0.62)),
                k.bCurve + 0.3, edgeBias, phase)
            : null;
        for (let x = 0; x < GW; x++) {
            const bh = back[x];
            if (bh > 0) {
                const cut = (x + bh + phase) % 2 === 0 ? 1 : 0;      // dither-broken top cell
                if (bh - cut > 0) P(x, GH - bh + cut, 1, bh - cut, DEEP, k.backA);
                if (bh > 2 && (x * 7 + seed) % 5 === 0) P(x, GH - 1 - bh, 1, 1, DEEP, 0.35);
            }
            if (mid && mid[x] > 0) {
                const mh = mid[x], cut = (x + mh + phase + 1) % 2 === 0 ? 1 : 0;
                if (mh - cut > 0) P(x, GH - mh + cut, 1, mh - cut, VOID, 0.85);
            }
        }
        // tall 1px flame slivers, only out near the left/right thirds
        if (k.spikes > 0 && mid) {
            let placed = 0;
            for (let x = 2; x < GW - 2 && placed < k.spikes; x++) {
                const t = x / (GW - 1);
                if ((t > 0.22 && t < 0.78) || rnd(x, seed + 29) < 0.88) continue;
                const sh = mid[x] + Math.max(3, Math.round(k.bMax * 0.1)) + (x % 3);
                P(x, GH - sh, 1, sh, VOID, 0.95);
                placed++;
            }
        }
        // sparse ember caps on tongue apexes, one E1 wink per beat
        const capsOn = mid || back;
        const capMin = mid ? 5 : Math.max(4, Math.round(k.bMax * 0.5));
        let capIdx = 0;
        for (let x = 1; x < GW - 1; x++) {
            if (!(capsOn[x] >= capMin && capsOn[x] >= capsOn[x - 1] && capsOn[x] > capsOn[x + 1])) continue;
            if ((capIdx + phase) % 3 === 0) {
                P(x, GH - 1 - capsOn[x], 1, 1, (capIdx === 0 && phase === 1) ? E1 : E0, 0.9);
            }
            capIdx++;
        }

        // --- (2) hanging void-folds (top) + drip tails --------------------------
        if (k.tMax > 0) {
            const tb = prof(GW, seed + 3, k.tMin, k.tMax, k.tSpan[0], k.tSpan[1], k.tCurve, edgeBias, phase);
            const tm = k.mid
                ? prof(GW, seed + 17, Math.max(2, Math.round(k.tMin * 0.7)), Math.max(3, Math.round(k.tMax * 0.6)),
                    Math.max(4, Math.round(k.tSpan[0] * 0.67)), Math.max(5, Math.round(k.tSpan[1] * 0.71)),
                    k.tCurve + 0.2, edgeBias, phase)
                : null;
            for (let x = 0; x < GW; x++) {
                const bh = tb[x];
                if (bh > 0) {
                    const cut = (x + bh + phase) % 2 === 0 ? 1 : 0;
                    if (bh - cut > 0) P(x, 0, 1, bh - cut, DEEP, k.backA);
                }
                if (tm && tm[x] > 0) {
                    const mh = tm[x], cut = (x + mh + phase + 1) % 2 === 0 ? 1 : 0;
                    if (mh - cut > 0) P(x, 0, 1, mh - cut, VOID, 0.85);
                }
            }
            if (k.drips > 0 && tm) {
                const apexes = [];
                for (let x = 1; x < GW - 1; x++) {
                    if (tm[x] >= 4 && tm[x] >= tm[x - 1] && tm[x] > tm[x + 1]) apexes.push(x);
                }
                for (let i = 0; i < Math.min(k.drips, apexes.length); i++) {
                    const x = apexes[Math.floor(i * apexes.length / Math.max(1, k.drips))];
                    const len = 3 + Math.floor(rnd(x, seed + 23) * 4) + ((i + phase) % 2);
                    P(x, tm[x], 1, len, VOID, 0.8);
                    if ((i + phase) % 3 === 0) P(x, tm[x] + len, 1, 1, E0, 0.85);   // ember drip tip
                }
            }
        }

        // --- (3) lateral pressure tongues; corners deepen by overlap ------------
        if (k.sideMax > 0) {
            const [ss0, ss1] = k.sideSpan;
            const sl = prof(GH, seed + 31, 2, k.sideMax, ss0, ss1, 1.0, sideBias, phase);
            const sr = prof(GH, seed + 37, 2, k.sideMax, ss0, ss1, 1.0, sideBias, phase);
            for (let y = 0; y < GH; y++) {
                const lb = sl[y];
                if (lb > 0) {
                    const cut = (y + lb + phase) % 2 === 0 ? 1 : 0;
                    if (lb - cut > 0) P(0, y, lb - cut, 1, DEEP, k.sideA);
                    if (k.mid) { const ml = Math.round(lb * 0.6); if (ml > 0) P(0, y, ml, 1, VOID, 0.8); }
                }
                const rb = sr[y];
                if (rb > 0) {
                    const cut = (y + rb + phase) % 2 === 0 ? 1 : 0;
                    if (rb - cut > 0) P(GW - (rb - cut), y, rb - cut, 1, DEEP, k.sideA);
                    if (k.mid) { const mr = Math.round(rb * 0.6); if (mr > 0) P(GW - mr, y, mr, 1, VOID, 0.8); }
                }
            }
        }

        // --- (4) detached void petals (drift ±1 cell with the phase) -----------
        for (let i = 0; i < k.petals; i++) {
            const e = i % 4, t = rnd(i, seed + 41), shape = PETALS[i % PETALS.length];
            const drift = ((i + phase) % 3) - 1;
            let px, py;
            if (e === 0) { px = 4 + Math.round(t * (GW - 12)); py = GH - 6 - Math.floor(rnd(i, seed + 43) * 5); }
            else if (e === 1) { px = 4 + Math.round(t * (GW - 12)); py = 2 + Math.floor(rnd(i, seed + 43) * 5); }
            else if (e === 2) { px = 2 + Math.floor(rnd(i, seed + 43) * 6); py = 6 + Math.round(t * (GH - 16)); }
            else { px = GW - 6 - Math.floor(rnd(i, seed + 43) * 6); py = 6 + Math.round(t * (GH - 16)); }
            py += drift;
            for (const [sx, sy] of shape) P(px + sx, py + sy, 1, 1, VOID, 0.88);
            if (i % 2 === 0) P(px + shape[0][0] + 1, py + shape[0][1] - 1, 1, 1, E0, 0.85);   // glint
        }
    }

    /** Offscreen surface for the baked darkening (null where none can be made). */
    static _makeCanvas(w, h) {
        try {
            if (typeof document !== 'undefined' && typeof document.createElement === 'function') {
                const c = document.createElement('canvas');
                c.width = w; c.height = h;
                return c;
            }
            if (typeof OffscreenCanvas !== 'undefined') return new OffscreenCanvas(w, h);
        } catch (_) { /* fall through to the direct painter */ }
        return null;
    }

    /**
     * Cached breathing layer for `phase`. The cache is keyed on viewport + tier and
     * each phase bakes lazily on first use, so a resize or a tier flip just rebuilds.
     */
    static _curseLayer(w, h, phase) {
        const tier = isPerfVfx() ? 2 : (isLiteVfx() ? 1 : 0);
        let C = SpriteManager._curse;
        if (!C || C.w !== w || C.h !== h || C.tier !== tier) {
            const px = Math.max(2, Math.round(Math.min(w, h) / 180));   // ~4px cell at 720p
            const GH = Math.ceil(h / px);
            C = SpriteManager._curse = {
                w, h, tier, px, GH, GW: Math.ceil(w / px),
                knobs: SpriteManager._curseKnobs(GH, tier),
                layers: [null, null, null],
                noCanvas: false,
            };
        }
        if (C.noCanvas) return null;
        if (C.layers[phase]) return C.layers[phase];
        const cv = SpriteManager._makeCanvas(w, h);
        const c2 = cv && cv.getContext ? cv.getContext('2d') : null;
        if (!c2) { C.noCanvas = true; return null; }
        c2.imageSmoothingEnabled = false;
        SpriteManager._cursePaintCells((x, y, cw, chh, color, a) => {
            c2.globalAlpha = a;
            c2.fillStyle = color;
            c2.fillRect(x * C.px, y * C.px, cw * C.px, chh * C.px);
        }, C.GW, C.GH, C.knobs, phase, CURSE_SEED);
        C.layers[phase] = cv;
        return cv;
    }

    /**
     * Screen-space AFK darkening: cursed pressure closing in from every edge.
     * `phase` (0..2) is the breathing beat — drive it off the same clock as the
     * intimidation aura so the whole state breathes together. Call in SCREEN space.
     */
    static drawIntimidationVignette(ctx, w, h, opts = {}) {
        const { intensity = 1, phase = 0 } = opts;
        const A = intensity < 0 ? 0 : intensity > 1 ? 1 : intensity;
        if (A <= 0 || !(w > 0) || !(h > 0)) return;
        const ph = ((Math.floor(phase) % 3) + 3) % 3;
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        const layer = SpriteManager._curseLayer(w, h, ph);
        if (layer) {
            ctx.imageSmoothingEnabled = false;      // 1:1 blit — the cells stay hard-edged
            ctx.globalAlpha = baseGA * A;
            ctx.drawImage(layer, 0, 0);
        } else {
            const C = SpriteManager._curse;         // headless fallback: paint the cells live
            SpriteManager._cursePaintCells((x, y, cw, chh, color, a) => {
                ctx.globalAlpha = baseGA * a * A;
                ctx.fillStyle = color;
                ctx.fillRect(x * C.px, y * C.px, cw * C.px, chh * C.px);
            }, C.GW, C.GH, C.knobs, ph, CURSE_SEED);
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    // =======================================================================
    // STAGE 7A-2C — "VOID-FRACTURE" BLACK-RED BOSS LIGHTNING (afk2_spec.md §B)
    // -----------------------------------------------------------------------
    // Anatomy: a VOID `#060409` crack-SHEATH flanking a 1px E2 `#e0263a` filament,
    // E3 `#ff5a4a` hot kinks at every direction change, E1 branches ending in a
    // single E0 tip. The path is 4px segments with deterministic ±jitter, FIXED
    // for the whole lifecycle so the arc fractures in place instead of writhing.
    //
    // Lifecycle: F0 ignite -> F1 flash -> F2 fracture -> F3 ash, where the ash
    // slivers SINK — the same downward language as the intimidation aura, so the
    // lightning reads as part of the state and never as heroic/anime lightning.
    //
    // Drawn in the boss's 46x48 MATRIX CELL space (same anchors as the aura), OVER
    // the sprite, so it can never be blue, never leave the aura footprint, never
    // reach the Hero, and never hide the silhouette.
    // =======================================================================

    static _bres(x0, y0, x1, y1) {
        const out = [];
        let dx = Math.abs(x1 - x0), dy = Math.abs(y1 - y0),
            sx = x0 < x1 ? 1 : -1, sy = y0 < y1 ? 1 : -1, err = dx - dy, x = x0, y = y0;
        for (;;) {
            out.push([x, y]);
            if (x === x1 && y === y1) break;
            const e2 = 2 * err;
            if (e2 > -dy) { err -= dy; x += sx; }
            if (e2 < dx) { err += dx; y += sy; }
        }
        return out;
    }

    /** Jittered arc path + its kink indices. Deterministic per seed, so memoized. */
    static _boltPath(x0, y0, x1, y1, seed, jx = 2, jy = 2) {
        if (!SpriteManager._bolts) SpriteManager._bolts = new Map();
        const key = `${x0},${y0},${x1},${y1},${seed},${jx},${jy}`;
        const hit = SpriteManager._bolts.get(key);
        if (hit) return hit;
        const rnd = SpriteManager._curseRnd;
        const pts = [[x0, y0]];
        const n = Math.max(2, Math.round(Math.hypot(x1 - x0, y1 - y0) / 4));   // 4px segments
        for (let i = 1; i < n; i++) {
            const t = i / n;
            pts.push([Math.round(x0 + (x1 - x0) * t + (rnd(i, seed) - 0.5) * 2 * jx),
                      Math.round(y0 + (y1 - y0) * t + (rnd(i, seed + 3) - 0.5) * 2 * jy)]);
        }
        pts.push([x1, y1]);
        const cells = [], kinks = [];
        for (let s = 0; s < pts.length - 1; s++) {
            const seg = SpriteManager._bres(pts[s][0], pts[s][1], pts[s + 1][0], pts[s + 1][1]);
            if (s > 0) seg.shift();
            cells.push(...seg);
            if (s < pts.length - 2) kinks.push(cells.length - 1);
        }
        const out = { cells, kinks };
        SpriteManager._bolts.set(key, out);
        return out;
    }

    /** Paint one arc in a lifecycle mode through `P(cellX, cellY, color, alpha)`. */
    static _renderBolt(P, bolt, mode, opts = {}) {
        const VOID = '#060409', SMK = '#1a1420',
              E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a';
        const { cells, kinks } = bolt;
        if (!cells.length) return;
        const { branches = [], seed = 7 } = opts;

        if (mode === 'ignite') {                     // 2x2 hot spark + 4 diagonals + hairline
            const [sx, sy] = cells[0];
            P(sx, sy, E3, 1); P(sx + 1, sy, E3, 1); P(sx, sy + 1, E3, 1); P(sx + 1, sy + 1, E3, 1);
            for (const [dx, dy] of [[-2, -2], [3, -2], [-2, 3], [3, 3]]) P(sx + dx, sy + dy, E2, 1);
            for (let i = 2; i < Math.min(8, cells.length); i++) P(cells[i][0], cells[i][1], VOID, 0.9);
            return;
        }
        if (mode === 'flash') {                      // full sheath + filament + kinks + branches
            for (let i = 0; i < cells.length; i++) {
                const [x, y] = cells[i];
                const p = cells[Math.max(0, i - 1)], nn = cells[Math.min(cells.length - 1, i + 1)];
                if (Math.abs(nn[1] - p[1]) >= Math.abs(nn[0] - p[0])) { P(x - 1, y, VOID, 0.85); P(x + 1, y, VOID, 0.85); }
                else { P(x, y - 1, VOID, 0.85); P(x, y + 1, VOID, 0.85); }
            }
            for (const [x, y] of cells) P(x, y, E2, 1);
            for (const i of kinks) { const [x, y] = cells[i]; P(x, y, E3, 1); P(x, y - 1, E3, 1); }
            for (const b of branches) {
                const from = cells[Math.min(cells.length - 1, Math.floor(b.frac * cells.length))];
                const sub = SpriteManager._boltPath(from[0], from[1], from[0] + b.dx, from[1] + b.dy, seed + 11, 1, 1);
                sub.cells.forEach(([x, y], i2) => {
                    P(x, y - 1, VOID, 0.7);
                    P(x, y, i2 === sub.cells.length - 1 ? E0 : E1, 1);   // single E0 tip
                });
            }
            return;
        }
        if (mode === 'fracture') {                   // filament broken into runs
            const kset = new Set(kinks);
            for (let i = 0; i < cells.length; i++) {
                if (i % 5 >= 3) continue;
                const [x, y] = cells[i];
                P(x, y, kset.has(i) ? E2 : E1, 1);
                if (i % 5 === 0) P(x, y - 1, VOID, 0.8);
            }
            const m = cells[Math.floor(cells.length / 2)];
            P(m[0] + 2, m[1] - 2, E0, 0.85); P(m[0] - 2, m[1] + 3, E0, 0.7);
            return;
        }
        // ash: tattered slivers SINKING off the dead arc (the aura's sink language)
        for (let i = 0; i < cells.length; i += 4) {
            const [x, y] = cells[i];
            const len = 2 + ((i >> 2) % 2);
            for (let j = 0; j < len; j++) P(x, y + 1 + j, ((i >> 2) % 2) ? SMK : E0, 0.9);
        }
        const m = cells[Math.floor(cells.length / 2)];
        P(m[0] + 2, m[1] + 2, E0, 0.7);
    }

    /**
     * The boss's intimidation lightning. `arcs` is a render-only list of live arcs
     * ({x0,y0,x1,y1,seed,jx,jy,branches,ground,mode,fade}) in matrix cell coords;
     * the caller schedules them off the heartbeat. Anchored on the sprite matrix
     * ORIGIN, exactly like drawIntimidationAura. Draw AFTER the sprite.
     *
     * Tiering (afk2_spec §C, Stage RE-3.5 correction): normal 2 concurrent arcs
     * (+branches), lite 1 (branchless), performance 1 minimal branchless fork.
     * Performance keeps ONE clearly-visible black-red fork rather than dropping to
     * micro-sparks only, so the AFK lightning identity is never completely lost in
     * any tier (RE-3.5 requirement). The chest/blade/plant micro-sparks are still
     * drawn in EVERY tier — the identity that survives even alongside the deepest cut.
     */
    static drawVoidFractureArcs(ctx, originX, originY, px, arcs, opts = {}) {
        const { flip = false, intensity = 1, sparkPhase = 0, sparks = true } = opts;
        if (intensity <= 0) return;
        const LITE = isLiteVfx(), PERF = isPerfVfx();
        const E0 = '#6e0f1c', E1 = '#a8182a', E2 = '#e0263a', E3 = '#ff5a4a';
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        const cell = (cx, cy, cw, chh, color, a) => {
            const fx = flip ? (45 - (cx + cw - 1)) : cx;
            ctx.globalAlpha = baseGA * a * intensity;
            ctx.fillStyle = color;
            ctx.fillRect(originX + fx * px, originY + cy * px, cw * px, chh * px);
        };

        // Idle-gap micro-sparks: chest core / beside the blade / plant point.
        if (sparks) {
            const sp = [[22, 13, E2, 1], [32, 30, E3, 1], [29, 41, E0, 0.9]];
            for (let i = 0; i < sp.length; i++) {
                if ((i + sparkPhase) % 3 === 0) continue;      // two of three, rotating
                cell(sp[i][0], sp[i][1], 1, 1, sp[i][2], sp[i][3]);
            }
        }

        const cap = PERF ? 1 : (LITE ? 1 : 2);   // RE-3.5: perf keeps 1 minimal fork, never 0
        for (let i = 0; i < arcs.length && i < cap; i++) {
            const a = arcs[i];
            const fade = a.fade == null ? 1 : a.fade;
            const bolt = SpriteManager._boltPath(a.x0, a.y0, a.x1, a.y1, a.seed, a.jx, a.jy);
            SpriteManager._renderBolt(
                (cx, cy, color, al = 1) => cell(cx, cy, 1, 1, color, al * fade),
                bolt, a.mode, { branches: LITE ? [] : (a.branches || []), seed: a.seed },
            );
            if (a.ground && a.mode === 'flash') {              // it ends on the floor
                cell(a.x1 - 3, a.y1, 2, 1, E1, fade);
                cell(a.x1 + 2, a.y1, 2, 1, E1, fade);
            }
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    /**
     * The wall-bounce read (afk_spec §4, wall cells 1-3). The Hero is compressed
     * into the wall and REBOUNDS: a cold steel rim flash on the stone, dark umbral
     * chevrons peeling off it, and warm stone dust at its base. Deliberately carries
     * NO ember red and NO hit-flash, so it never reads as a damaging attack.
     *
     * @param {number} wallX  the wall FACE x (the side the Hero struck).
     * @param {number} inwardDir  +1 if the wall is on the left, -1 if on the right.
     */
    static drawWallRepulse(ctx, wallX, groundY, inwardDir = 1, opts = {}) {
        const { progress = 0, height = 48 } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1) return;
        const PERF = isPerfVfx(), LITE = isLiteVfx();
        const PX = Math.max(2, Math.round(height / 24));
        const d = inwardDir >= 0 ? 1 : -1;                    // chevrons peel inward
        const f = 1 - p;
        const baseGA = ctx.globalAlpha;
        const ox = Math.round(wallX), oy = Math.round(groundY - height);
        ctx.save();
        ctx.shadowBlur = 0;
        const R = (gx, gy, gw, gh, color, a = 1) => {
            ctx.globalAlpha = baseGA * a * f;
            ctx.fillStyle = color;
            ctx.fillRect(ox + (d > 0 ? gx : -(gx + gw)) * PX, oy + gy * PX, gw * PX, gh * PX);
        };
        R(0, 2, 1, 20, '#7c88a0');                            // steel impact rim on the stone
        if (!PERF) {
            [[2, 4], [3, 11], [2, 18]].forEach(([gx, gy]) => {
                R(gx, gy, 2, 1, '#14101c');
                if (!LITE) R(gx + 2, gy + 1, 2, 1, '#1a1420');
            });
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
        // Warm stone dust puff at the wall base (the approved sampler R2C3 dust).
        SpriteManager.drawLandingDust(ctx, wallX + d * PX * 3, groundY, { progress: p, px: 2 });
    }

    /**
     * The Hero's hesitation arc (afk_spec §7): the cold line he will not cross.
     * Steel ground dashes toward the Boss with one icy tick and a held-breath
     * glint. Hero-owned palette (steel + cold blue) — never ember, never stars,
     * and nothing like the Fear-Strike crumple.
     */
    static drawHesitationArc(ctx, x, feetY, dir = 1, opts = {}) {
        const { intensity = 1, px = 2 } = opts;
        if (intensity <= 0) return;
        const PERF = isPerfVfx(), LITE = isLiteVfx();
        const d = dir >= 0 ? 1 : -1;
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        const dashes = PERF ? [[6, 0], [14, -1], [22, -1]] : [[4, 0], [11, -1], [18, -1], [25, -1], [32, 0]];
        const icy = PERF ? 1 : 2;
        dashes.forEach(([gx, gy], i) => {
            ctx.globalAlpha = baseGA * intensity * (i === icy ? 1 : 0.8);
            ctx.fillStyle = i === icy ? '#7fd4ff' : '#2e3444';
            ctx.fillRect(Math.round(x + d * gx * px), Math.round(feetY - px + gy * px), 3 * px, px);
        });
        if (!LITE) {                                          // held-breath glint
            ctx.globalAlpha = baseGA * intensity;
            ctx.fillStyle = '#b8ecff';
            ctx.fillRect(Math.round(x + d * (dashes[icy][0] + 1) * px), Math.round(feetY - 4 * px), px, px);
        }
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }

    /**
     * Denial shards (afk_spec §8): after the Boss swallows a hit mid-snap/plant it
     * SHEDS ember fragments instead of staggering. Drawn over the umbral silhouette
     * the entity paints for the denial tint.
     */
    static drawDenialShards(ctx, x, bodyCY, opts = {}) {
        const { progress = 0, size = 144 } = opts;
        const p = progress < 0 ? 0 : progress > 1 ? 1 : progress;
        if (p >= 1 || isPerfVfx()) return;
        const PX = Math.max(2, Math.round(size / 48));
        const baseGA = ctx.globalAlpha;
        ctx.save();
        ctx.shadowBlur = 0;
        ctx.globalAlpha = baseGA * (1 - p);
        ctx.fillStyle = '#6e0f1c';
        const drop = Math.round(p * 10);
        [[-11, -14], [-6, 4], [9, -8], [12, 8]].forEach(([gx, gy]) => {
            ctx.fillRect(Math.round(x + gx * PX), Math.round(bodyCY + (gy + drop) * PX), PX, 2 * PX);
        });
        ctx.globalAlpha = baseGA;
        ctx.restore();
    }
}

// ---------------------------------------------------------------------------
// SpriteAnimator — frame timing only (no state decisions).
// ---------------------------------------------------------------------------
// The game is frame-based (one update/draw per rAF), so the animator advances by
// whole game-frames: `hold` = how many game-frames each sprite frame is shown.
// Entities call set(name, hold) to choose the clip, tick() once per draw, then
// current() to fetch the frame. Switching clips resets to frame 0.
export class SpriteAnimator {
    constructor(sprites, hold = 6) {
        this.sprites = sprites;
        this.hold = hold;
        this.name = null;
        this.frame = 0;
        this._count = 0;
    }

    set(name, hold = this.hold) {
        if (name !== this.name) {
            this.name = name;
            this.frame = 0;
            this._count = 0;
        }
        this._hold = hold;
    }

    tick() {
        const frames = this.sprites[this.name];
        if (!frames || frames.length <= 1) return;
        if (++this._count >= (this._hold || this.hold)) {
            this._count = 0;
            this.frame = (this.frame + 1) % frames.length;
        }
    }

    current() {
        const frames = this.sprites[this.name];
        if (!frames || !frames.length) return null;
        return frames[this.frame % frames.length];
    }
}
